ISNULL(', ' +(LTRIM(RTRIM(vps.Language3))),'') + 
ISNULL(', ' +(LTRIM(RTRIM(vps.Language4))),'') + 
ISNULL(', ' +(LTRIM(RTRIM(vps.Language5))),''),1,2,''),1,255) --REMOVE comma (',') FROM 1st STATEMENT() SIR EVAN ON 20160721 STUFF([SOURCE STRING],[START POSITION],[HOW MANY CHAR() TO REPLACE() / SUBSTITUTE()],[WHAT TO ADD TO THE STRING]) --[START POSITION] default(s) TO 1
