DROP TABLE IF EXISTS #COVER_FOR_NO_COVG -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT 'Y' AS [USE_HOSPITALIST]
,vpa.InDirectory
,(LTRIM(RTRIM(vpd.NationalProviderID))) AS ORIGINALnpi
,(LTRIM(RTRIM(CAST(vpd.LastName AS varchar(255))))) AS ORIGINALlnm
,(LTRIM(RTRIM(CAST(vpd.FirstName AS varchar(255))))) AS ORIGINALfnm
,(LTRIM(RTRIM(vpd.PractitionerID))) AS ORIGINALlkup
,(LTRIM(RTRIM(vpd.PractitionerID))) AS [lookup_key]
,(LTRIM(RTRIM(vpd.PractitionerID))) AS lky
,(LTRIM(RTRIM(CAST(vpcp.CoveringPractitionerID AS varchar(25))))) AS [COVERlkup ]
,(LTRIM(RTRIM(CAST(vpcp.CoveringPhysicianName AS varchar(255))))) AS [COVERNM]
,(LTRIM(RTRIM(CAST(vpcp.CoveringPractitionerID AS varchar(25))))) AS ALTlky --aka 'COVERlkup'
,(LTRIM(RTRIM(vpa.InstitutionID))) AS [HOSP_lookup_key]
,CAST(NULL AS varchar(25)) AS HOSPNPI --QUPD
,(LTRIM(RTRIM(vpa.InstitutionName))) AS [HOSPNM]
,(LTRIM(RTRIM(vpa.InstitutionName))) AS 'HOSP_name'
,CAST(NULL AS varchar(25)) AS HOSPITAL_ID --QUPD the QNXT provid
,CAST(NULL AS varchar(5)) AS [HOSPABBREV] -- QUPD ;WITH() USE EITHER #WCE [ABBREV] LOGIC
,CAST(NULL AS varchar(25)) AS [NPIhospital] -- QUPD
,CAST(NULL AS varchar(25)) AS [CA_License] -- QUPD
,(LTRIM(RTRIM(vpa.InstitutionName))) AS [company]
,CAST(NULL AS varchar(5)) AS [providence] -- QUPD ;WITH() USE EITHER #WCE [ABBREV] LOGIC
