DROP TABLE IF EXISTS #INITIALS -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')
 
;WITH INITIALS AS --;WITH() LIKE '%CREATION OF [tempdb] TABLE%'  # FROM JL
( --INITIATE ...
SELECT lookup_key,company
,LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))) AS [FIRST_INITIAL_SOURCE]
,SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255) AS [SECOND_INITIAL_SOURCE] -- REPLACE() / SUBSTITUTE() the [SOURCE] FROM PREVIOUS ... 
,SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255) AS [THIRD_INITIAL_SOURCE]  --REPLACE() / SUBSTITUTE() the [SOURCE] FROM PREVIOUS ... 
,SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255))),1)+1,255) AS [FOURTH_INITIAL_SOURCE]  --REPLACE() / SUBSTITUTE() the [SOURCE] FROM PREVIOUS ... 
,SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),CHARINDEX(' ',LTRIM(RTRIM(SUBSTRING(LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),CHARINDEX(' ',LTRIM(RTRIM(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM([company]))),'-',''),'(',''),' OF ',''),' AND ',''))),1)+1,255))),1)+1,255))),1)+1,255))),1)+1,255) AS [FIFTH_INITIAL_SOURCE] -- REPLACE() / SUBSTITUTE() the [SOURCE] FROM PREVIOUS ... 
FROM #HOSPpriv
) --CONCLUDE ...
SELECT (SUBSTRING(LTRIM(RTRIM([FIRST_INITIAL_SOURCE])),1,1) --1ST INITIAL ...
+''+ 
CASE
WHEN LTRIM(RTRIM([SECOND_INITIAL_SOURCE])) = LTRIM(RTRIM([FIRST_INITIAL_SOURCE]))
THEN ''
ELSE SUBSTRING(LTRIM(RTRIM([SECOND_INITIAL_SOURCE])),1,1)--2ND INITIAL 
END
+''+ 
CASE
WHEN LTRIM(RTRIM([THIRD_INITIAL_SOURCE])) = LTRIM(RTRIM([SECOND_INITIAL_SOURCE]))
THEN ''
ELSE SUBSTRING(LTRIM(RTRIM([THIRD_INITIAL_SOURCE])),1,1) --3RD INITIAL ...
END
+''+ 
CASE
WHEN LTRIM(RTRIM([FOURTH_INITIAL_SOURCE])) = LTRIM(RTRIM([THIRD_INITIAL_SOURCE]))
THEN ''
ELSE SUBSTRING(LTRIM(RTRIM([FOURTH_INITIAL_SOURCE])),1,1) --4TH INITIAL ...
END
+''+ 
CASE
WHEN LTRIM(RTRIM([FIFTH_INITIAL_SOURCE])) = LTRIM(RTRIM([FOURTH_INITIAL_SOURCE]))
THEN ''
ELSE SUBSTRING(LTRIM(RTRIM([FIFTH_INITIAL_SOURCE])),1,1) --5TH INITIAL ...
END) AS [ABBREVIATIONis],* --NESTED()
INTO #INITIALS
