UPDATE #HOSPpriv
SET NPIhospital = (LTRIM(RTRIM(hosnpi.[NPIis])))
,HOSPNPI = (LTRIM(RTRIM(hosnpi.[NPIis])))
-- SELECT TOP 100 *  -- CHECK 1st
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM #HOSPpriv AS hp
	INNER JOIN
	( -- INITIATE ...
	SELECT DISTINCT vpl.LocationName,vp.PracticeName,vp.LegalName,LTRIM(RTRIM(vp.NationalProviderID)) AS altNPIis ,REPLACE((LTRIM(RTRIM(vf.TaxIDNumber))),'-','') AS vfPROVTAXID ,CASE WHEN vpl.NationalProviderID IS NULL 	AND (LTRIM(RTRIM(vf.FacilityStatus))) LIKE 'ACTIVE%' 	AND (LTRIM(RTRIM(vf.ApplicationStatus))) LIKE 'ACTIVE%' THEN LTRIM(RTRIM(vf.NationalProviderID)) ELSE LTRIM(RTRIM(vpl.NationalProviderID)) END AS [NPIis] 
	FROM eVips_chgcv.dbo.vwPractices AS vp 	
		INNER JOIN eVips_chgcv.dbo.vwPracticeLocations AS vpl ON vp.PracticeID = vpl.PracticeID 		
			LEFT JOIN eVips_chgcv.dbo.vwFacilities AS vf ON (LTRIM(RTRIM(vf.FacilityName))) = (LTRIM(RTRIM(vpl.LocationName))) 			
				OR (LTRIM(RTRIM(vf.FacilityName))) = (LTRIM(RTRIM(vp.PracticeName))) 	
	WHERE CASE 
	WHEN vpl.NationalProviderID IS NULL 	
		AND (LTRIM(RTRIM(vf.FacilityStatus))) LIKE 'ACTIVE%' 	
		AND (LTRIM(RTRIM(vf.ApplicationStatus))) LIKE 'ACTIVE%' 
	THEN LTRIM(RTRIM(vf.NationalProviderID)) 
	ELSE LTRIM(RTRIM(vpl.NationalProviderID)) 
	END IS NOT NULL
	) -- CONCLUDE ...
	AS hosnpi ON (LTRIM(RTRIM(ISNULL(hp.HOSPNM,'')))) = (LTRIM(RTRIM(ISNULL(hosnpi.LocationName,''))))
		OR (LTRIM(RTRIM(ISNULL(hp.HOSPNM,'')))) = (LTRIM(RTRIM(ISNULL(hosnpi.PracticeName,''))))
		OR (LTRIM(RTRIM(ISNULL(hp.HOSPNM,'')))) = (LTRIM(RTRIM(ISNULL(hosnpi.LegalName,''))))
WHERE NPIhospital IS NULL		

