ELSE ''
END
+
CASE
WHEN [6_START] IS NOT NULL
THEN ', FRI '+[6_START]+' - '+[6_END]
ELSE ''
END
+
CASE
WHEN [7_START] IS NOT NULL
THEN ', SAT  '+[7_START]+' - '+[7_END]
ELSE ''
END
+
CASE
WHEN [1_START] IS NOT NULL
THEN ', SUN  '+[1_START]+' - '+[1_END]
ELSE ''
END
END --NESTED()
FROM #HOURS_FAC AS h

