DROP TABLE IF EXISTS #INNETWORK_FAC -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT 'FACILITY(-ies)' AS [NOTE(s)]
-- ,'Y' AS [INDIRECTORY]
,(LTRIM(RTRIM(vlp.InDirectory))) AS [INDIRECTORY]
,(LTRIM(RTRIM(vp.Archived))) AS [vpARCHIVED]
,(LTRIM(RTRIM(vp.PracticeStatus))) AS [vpPRACTICESTATUS]
,(LTRIM(RTRIM(vp.ApplicationStatus))) AS [vpAPPLICATIONSTATUS]
,(LTRIM(RTRIM(vpl.Archived))) AS [vplARCHIVED]
,(LTRIM(RTRIM(vpl.LocationTypeName))) AS [vplLOCATIONTYPENAME]
,(LTRIM(RTRIM(vlp.LocationTypeName))) AS [vlpLOCATIONTYPENAME]
,(LTRIM(RTRIM(vlp.Archived))) AS [vlpARCHIVED]
,(LTRIM(RTRIM(vlp.StatusTypeName))) AS [vlpSTATUSTYPENAME]
,(LTRIM(RTRIM(vlp.ServiceTypeName))) AS [vlpSERVICETYPENAME]
,CAST(NULL AS nvarchar(5)) AS [providence] -- see #WCE ABBREV LOGIC ...
,CAST(NULL AS nvarchar(100)) AS ID -- NPI IFERROR(VLOOKUP()) COL(s)
,(LTRIM(RTRIM(vp.PracticeTypeName))) AS [VP_plan_type] -- per MS. SANDRA email ON 20180131 '...Yes.  All of the plan types for facilities should come from the products not the practices....'
,(LTRIM(RTRIM(vlp.PracticeTypeName))) AS [VLP_plan_type] -- per MS. SANDRA email ON 20180131 '...Yes.  All of the plan types for facilities should come from the products not the practices....'
,(LTRIM(RTRIM(vlp.ProductTypeCode))) AS [VLP_Alt_plan_type] -- per MS. SANDRA email ON 20180131 '...Yes.  All of the plan types for facilities should come from the products not the practices....'
,(LTRIM(RTRIM(vlp.ProductTypeName))) AS [VLP_full_plan_name] -- per MS. SANDRA email ON 20180131 '...Yes.  All of the plan types for facilities should come from the products not the practices....'
,(LTRIM(RTRIM(vp.PracticeTypeName))) AS [plan_type] -- per MS. SANDRA email ON 20180131 '...Yes.  All of the plan types for facilities should come from the products not the practices....'
,(LTRIM(RTRIM(vlp.ProductName))) AS [plan_name]
,CAST(NULL AS nvarchar(5)) AS [committie] -- ???
,vp.PracticeName,vpl.LocationName,vp.LegalName AS [VPLegalName],vpl.LegalName AS [VPLLegalName]
--,(LTRIM(RTRIM(vp.PracticeName))) AS [HospitalName]
--,(LTRIM(RTRIM(vp.PracticeName))) AS [FacilityName]
,(LTRIM(RTRIM(vpl.LocationName))) AS [HospitalName]
,(LTRIM(RTRIM(vpl.LocationName))) AS [FacilityName]
,(LTRIM(RTRIM(vpl.LocationName))) AS [Clinic Name]
,(LTRIM(RTRIM(vpl.LocationName))) AS [Pharmacy Name] -- We have most of the NPIs for the clinics.  They are located in the NPI field in the address master
--,(LTRIM(RTRIM(vp.LegalName))) AS [DBA]
,(LTRIM(RTRIM(vp.PracticeID))) AS [DBAPracticeID]
,(LTRIM(RTRIM(vp.PracticeName))) AS [DBA]
,CAST(NULL AS nvarchar(255)) AS [userdef_1]  --QUPD ;WITH() ??? ,(LTRIM(RTRIM(address.userdef_1))) AS userdef_1
,CAST(NULL AS nvarchar(25)) AS [MRI_MAMMO_INDICATOR] -- ,(LTRIM(RTRIM(address.userdef_1))) AS userdef_1
,'All Record Types' AS [Specialist Record Type]
-- ,LTRIM(RTRIM(vpl.NationalProviderID)) AS NPIis
,LTRIM(RTRIM(vp.NationalProviderID)) AS altNPIis
,REPLACE((LTRIM(RTRIM(vf.TaxIDNumber))),'-','') AS vfPROVTAXID
,CASE
WHEN vpl.NationalProviderID IS NULL
	AND (LTRIM(RTRIM(vf.FacilityStatus))) LIKE 'ACTIVE%'
	AND (LTRIM(RTRIM(vf.ApplicationStatus))) LIKE 'ACTIVE%'
THEN LTRIM(RTRIM(vf.NationalProviderID))
ELSE LTRIM(RTRIM(vpl.NationalProviderID)) 
END AS [NPIis]
,CAST(NULL AS nvarchar(25)) AS [CA_License]
,(LTRIM(RTRIM(vp.PracticeName))) AS [ASSOCIATION GROUP]
,CAST(NULL AS nvarchar(255)) AS [CULTURAL COMPETENCE] -- 'FAC [CULTURAL COMPETENCE] ???' - YOUNG LADY LAURA CONFIRMED PROV(s) ONLY ON 20171011
,CASE
WHEN LTRIM(RTRIM(vlp.ProductName)) LIKE '%MEDICAL%'
THEN 'CL1'
WHEN LTRIM(RTRIM(vlp.ProductName)) LIKE '%MEDICAR%'
THEN 'MCR'
WHEN LTRIM(RTRIM(vlp.ProductName)) LIKE '%CMC%'
THEN 'CMC'
ELSE CAST(NULL AS nvarchar(MAX))
END AS [Participating Network]
,CASE
WHEN LTRIM(RTRIM(vlp.ProductName)) LIKE '%MEDICAL%'
THEN 'MEDI_CAL'
WHEN LTRIM(RTRIM(vlp.ProductName)) LIKE '%MEDICAR%'
THEN 'Communicare_Advantage'
WHEN LTRIM(RTRIM(vlp.ProductName)) LIKE '%CMC%'
THEN 'CMC'
ELSE CAST(NULL AS nvarchar(MAX))
END AS [Name of Network]
,CAST(NULL AS nvarchar(100)) AS [HealthPlanID_for_PlanToPlanContract]
,CAST(NULL AS nvarchar(100)) AS [Language] -- see '#LANGUAGEs_FAC' FOR FUTURE QUPD(s) SYNTAX
,CAST(NULL AS nvarchar(100)) AS [Language (Other)]
,CAST(NULL AS nvarchar(100)) AS [Language1]
,CAST(NULL AS nvarchar(100)) AS [Language2]
,CAST(NULL AS nvarchar(100)) AS [Language3]
,CAST(NULL AS nvarchar(100)) AS [Language4]
,CAST(NULL AS nvarchar(100)) AS [Language5]
,CASE
WHEN SUBSTRING((LTRIM(RTRIM(vpl.TwentyFourHourCoverage))),1,1) IN ('Y') -- USE THIS CASE WHEN THEN ELSE END ONLY FOR HOS / SNF
THEN '7 Days a Week, 24 Hours a Day'
ELSE (LTRIM(RTRIM(h.[Office Hour(s)])))
END AS [Office Hour(s)],vpl.TwentyFourHourCoverage
-- ,CAST(NULL AS nvarchar(255)) AS [Accessibility] -- HARDCODED LIKE VIPs vwLocationServices
-- ,CAST(NULL AS nvarchar(255)) AS [Accessibility Category(ies)] -- HARDCODED LIKE VIPs
,acc.[Accessibility] -- HARDCODED LIKE VIPs vwLocationServices
,acc.[Accessibility Category(ies)] -- HARDCODED LIKE VIPs
--,CAST(NULL AS nvarchar(25)) [AGE RESTRICTION]AS  --QUPD / CASE WHEN THEN ELSE END... USE pcp.specialty AND pcp.age_restriction AND pcp.age-restriction2
,ager.[AGE RESTRICTION]
,'Yes' AS [HANDICAP_ACCESSIBLE] -- QUPD ;WITH() ??? DFLT VAL() ... Per S. Coleman ON 20160719 email: 'ADA' (Amercican Disability Act - footnote(s)) Handicap Accessible: 'Yes' --DFLT VAL() status of the pharmacies.  Please add to the printed and online file this default for pharmacies only (excluding mail order). unless an “N” is placed in address: group_region. I put an N in Drug Co Pharmacy so you can test it.  We will call the few pharmacies this afternoon that have an “N”.  I saw one error in the data received. Walter will default that field to yes.  He will put no if we have an “N”. Of the approx 400 pharmacies,we are calling ON about 50 right now
,'NA' AS [Percentage of Time Allocated to Plans Medi-Cal Members] -- Percentage of provider's total work hours spent at clinic.  If unknown,enter "NA."
,'Y' AS [Traditional and/or Safety Net Provider] -- Y/N to specify if provider is Traditional and/or Safety Net Provider
,'N' AS [Specialist Serves as PCP to SPD?] -- Y/N to specify if Specialist Serves as PCP to SPD? 
,'N' AS [Telehealth Provider (Y/N)] -- All fields listed below are required. Required fields MUST be completed or contain a value of "0" of "NA" (Except for "Plan-to-Plan Contract" field)
,(LTRIM(RTRIM(vpl.LineNumber1))) AS [address1]
,(LTRIM(RTRIM(vpl.LineNumber2))) AS [address2]
,(LTRIM(RTRIM(vpl.LineNumber3))) AS [address3]
,CASE
WHEN ((LTRIM(RTRIM(vpl.LineNumber2))) IN ('')
	OR vpl.LineNumber2 IS NULL)
THEN (LTRIM(RTRIM(vpl.LineNumber1)))
ELSE (RTRIM(LTRIM(vpl.LineNumber1)))+' '+(RTRIM(LTRIM(vpl.LineNumber2)))
END AS [Address]
,(LTRIM(RTRIM(vpl.City))) AS [CityIs]
/* ,CASE
WHEN (LTRIM(RTRIM(zip.County))) LIKE 'SD%'
THEN 'SAN DIEGO'
ELSE (LTRIM(RTRIM(zip.County)))
END AS [CountyIs]
,CASE
WHEN (LTRIM(RTRIM(zip.County))) LIKE 'SD%'
THEN 'SAN DIEGO'
ELSE (LTRIM(RTRIM(zip.County)))
END AS [County] */
-- ,LTRIM(RTRIM(ISNULL(addcounty.[County],'Unknown'))) AS [CountyIs]
-- ,LTRIM(RTRIM(ISNULL(addcounty.[County],'Unknown'))) AS [County]
,TRY_CONVERT(varchar(255),NULL) AS [CountyIs]
,TRY_CONVERT(varchar(255),NULL) AS [County]
,(LTRIM(RTRIM(vpl.[State]))) AS StateIs
,CASE
WHEN SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,1) = '0'
THEN '0'+ SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),2,4)
WHEN SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,1) = '00'
THEN '00'+ SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),3,3)
ELSE  SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,5) 
END AS [Zip Code]
,(LTRIM(RTRIM(ISNULL(regionis.RegionTypeName,'')))) AS [REGION]
-- ,CAST(NULL AS nvarchar(100)) AS [REGION] -- zipcodes [TABLE] regiontypename
,'Please use the TRS Relay number 711.' AS [TTY] -- AFTERHOURS IN Location Phones
,CAST(NULL AS nvarchar(15)) AS [DepartmentPhone] -- [Department Number]
,CAST(NULL AS nvarchar(15)) AS [Telephone Number]
,CAST(NULL AS nvarchar(15)) AS [FAXnumber]
,CAST(NULL AS nvarchar(100)) AS [HospitalSystem]
,(LTRIM(RTRIM(vp.PracticeName))) AS [Alt. Clinic Name]
,(LTRIM(RTRIM(vp.PracticeName))) AS [ClinicNameAgain]
,LTRIM(RTRIM(vpl.NationalProviderID)) AS [Clinic NPI]
,CAST((LTRIM(RTRIM(vpl.Notes))) AS nvarchar(25)) AS [Clinic QNXT provid] -- aka SITE CODE eVips_chgcv.dbo.vwPracticeLocations CHANGED TO ,(LTRIM(RTRIM(spe.LocationID))) AS [Clinic QNXT provid] -- -Per S. Coleman email ON 20171229 '...Site code should be eVIPs unique Location ID ...' BELOW ;WITH CREATION OF PROVDIR_ [TABLE(s)]!!!
,(LTRIM(RTRIM(vpl.Notes))) AS [lookup_name]
,CAST(NULL AS nvarchar(5)) AS [HOSPabbrev] -- see #WCE ABBREV LOGIC ...
,CAST(NULL AS int) AS [age_restriction] -- QUPD ;WITH() vwLocationProductLimitations
,CAST(NULL AS int) AS [age_restriction2] --QUPD ;WITH() vwLocationProductLimitations
,'NA' AS [Percentage of Time Spent at Clinic] -- Percentage of provider's total work hours spent at clinic.  If unknown,enter "NA."
,CASE
WHEN (LTRIM(RTRIM(vlp.ProductPanelStatusTypeName))) !='N'
THEN 'Y'
ELSE 'N'
END AS [Accepting New Medi-Cal Members/ Referrals] -- cert_provider.panel_status OR QUPD ;WITH()
,(LTRIM(RTRIM(vlp.ProductPanelStatusTypeCode))) AS [panel_status_code]
,(LTRIM(RTRIM(vlp.ProductPanelStatusTypeName))) AS [panel_status]
,CAST(NULL AS int) AS [Total Number of Medi-Cal Members Provider Will Accept from Plan] -- UPDATE in .xlsx ???
