,CAST(NULL AS int) AS [Current Number of Plan Medi-Cal Members Assigned to Clinic] -- QUPD SEQUENCE
,'N' AS [Full Time Equivalent (FTE)] -- QUPD ;WITH() #FTE per NETWORK ADEQUACY CALL ON 20170302
,(LTRIM(RTRIM(vpl.PracticeTypeName))) AS [Type of Service] -- ,'Free Standing - Primary and/or Specialty Care' AS [Type of Service]
,(LTRIM(RTRIM(vlp.focus))) AS [Type of Service FOCUS] -- ,'Free Standing - Primary and/or Specialty Care' AS [Type of Service]
