,CAST(NULL AS nvarchar(100)) AS TRUE_CLINICname --,LTRIM(RTRIM(mcred.group_desc)) AS [Clinic Name]
,CAST(NULL AS nvarchar(15)) AS TRUE_CLINICnpi --,'NA' AS [Clinic NPI] -- All fields listed below are required. Required fields MUST be completed or contain a value of "0" of "NA" (Except for "Plan-to-Plan Contract" field)
,CAST(NULL AS nvarchar(15)) AS [Available Bed Count]
,CAST(NULL AS nvarchar(15)) AS [Licensed Bed Count]
,CAST(NULL AS nvarchar(15)) AS [Staffed Bed Count]
,CASE
WHEN (LTRIM(RTRIM(CAST(vpl.website AS nvarchar(255))))) LIKE 'WWW%'
	OR (LTRIM(RTRIM(CAST(vpl.website AS nvarchar(255))))) LIKE 'HEALTH%'
	OR (LTRIM(RTRIM(CAST(vpl.website AS nvarchar(255))))) LIKE 'PROVIDERS%'
	OR (LTRIM(RTRIM(CAST(vpl.website AS nvarchar(255))))) LIKE '%HTTP%'
THEN (LTRIM(RTRIM(CAST(vpl.website AS nvarchar(255)))))
ELSE 'URL NOT PRESENT'
END AS [URL_WEBSITE]
,vlp.focus
,(LTRIM(RTRIM(vp.PracticeID))) AS 'lookup_key',vlp.ProductID,vlp.ProductName,vp.PracticeID,vpl.LocationID,vpl.AddressID --see vwPractitionerLocationHours
,vea.TableName,vea.EntityCode,vea.EntityName,vea.EntityTypeCode,vea.EntityTypeName --ARRIVE AT ENTITY TYPE(s) FROM PROVDIR MEETING ON 20170920 SPECIFICALLY TO ID VSP PROV(s) ... --ProviderID = PractitionerID WHERE (LTRIM(RTRIM(vea.TableName))) LIKE '%Practit%' OR  ProviderID = PracticeID WHERE (LTRIM(RTRIM(vea.TableName))) LIKE '%Practice%'
,vls.ClassOrCategory --DEFINE PHARM TYPE(s)
,vls.ServiceTypeName,vls.ServiceCategoryTypeName --DEFINE FAC CHAPTER(s) ;WITHSELECT DISTINCT ServiceTypeName,[ServiceCategoryTypeName] FROM SQL07.evips_chgcv.dbo.vwLocationServices WHERE (LTRIM(RTRIM(ServiceTypeName))) LIKE '%GROUP%SPEC%'
,vlsfocus.Code1,vlsfocus.Code2,(LTRIM(RTRIM(vlsfocus.ServiceTypeName))) AS [vlsfocusSERVICETYPENAME],(LTRIM(RTRIM(vlsfocus.ServiceCategoryTypeName))) AS [vlsfocusSERVICECATEGORYTYPENAME] -- MIMIC cp.focus
,'RX' AS [Pharmacy] -- WAS ,(LTRIM(RTRIM(address.userdef_1))) AS [Pharmacy]  WHICH DELIVERED THE VAL OF 'RX' THEREFOR NOW() HARDCODE WILL SUFFICE
,CAST(NULL AS nvarchar(255)) AS [userdef_2]  --QUPD ;WITH() ???,address.userdef_2
-- ,CAST(NULL AS nvarchar(255)) AS [Pharmacy Type(s)]  --QUPD ;WITH() ??? ,(LTRIM(RTRIM(address.userdef_2))) AS [Pharmacy Type(s)] -- ,(LTRIM(RTRIM(address.userdef_2))) AS [Accessibility Category(ies)]
,(LTRIM(RTRIM(vlspharmtype.ServiceCategoryTypeName))) AS [Pharmacy Type(s)]
,(LTRIM(RTRIM(vlspharmtype.PracticeID))) AS [vlspharmtypePHARMACYPRACTICEID]
,(LTRIM(RTRIM(vlspharmtype.ClassOrCategory))) AS [vlspharmtypePHARMACYCLASS]
,(LTRIM(RTRIM(vlspharmtype.ServiceTypeName))) AS [vlspharmtypePHARMACYSERVICETYPE]
,(LTRIM(RTRIM(vlspharmtype.ServiceCategoryTypeName))) AS [vlspharmtypePHARMACYTYPENAME]
-- ,CAST(NULL AS nvarchar(255)) AS [Pharmacy Footnote(s)]  --QUPD ;WITH() ???,(LTRIM(RTRIM(address.npi_subpart))) AS [Pharmacy Footnote(s)]
,(LTRIM(RTRIM(vlspharmservice.ServiceCategoryTypeName))) AS [Pharmacy Footnote(s)]
,CAST(NULL AS nvarchar(255)) AS [npi_subpart]  --QUPD ;WITH() ??? ,address.npi_subpart
,(LTRIM(RTRIM(vlspharmservice.PracticeID))) AS [vlspharmservicePHARMACYPRACTICEID]
,(LTRIM(RTRIM(vlspharmservice.ClassOrCategory))) AS [vlspharmservicePHARMACYCLASS]
,(LTRIM(RTRIM(vlspharmservice.ServiceTypeName))) AS [vlspharmservicePHARMACYSERVICETYPE]
,(LTRIM(RTRIM(vlspharmservice.ServiceCategoryTypeName))) AS [vlspharmservicePHARMACYTYPENAME]
,profile.* --APL18-005 AND TIMELYACCESS
,CAST('No' AS varchar(3)) AS [CCSPaneledProvider] -- RFP TEAM REQUESTED ADD ON AS OF 20220121 PER DISCUSSION ;WITH() YOUNG LADY FRANCISCA, MS MONSE Y SIR RAUL
,CAST('Both' AS nvarchar(25)) AS [MedicaidMedicareFlag]
,CAST('Both' AS nvarchar(25)) AS [MMF]
,ftm.[FUTURE_TERM] -- 'This provider will remain in the network until Month, day, 20XX'
,TRY_CONVERT(nvarchar(1),'N') AS [Telehealth_Indicator] -- C007: APPLICABLE TO PROVIDERS ONLY!!! ADD - ON PER EMAIL FROM MS JOHANNA BASED UPON DHCS FINDING (LEVERAGE: APL 25-014 AND OR "PROVDIR Telehealth Indicator evips location .msg")
INTO #INNETWORK_FAC
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT  vlp.Focus,vlsfocus.Code1,vlsfocus.Code2,vp.Archived,vp.PracticeStatus,vp.ApplicationStatus,vpl.Archived,vpl.LocationTypeName,vp.PracticeTypeName,* -- CHECK 1st
-- SELECT * FROM eVips_chgcv.dbo.vwPracticeLocations -- CHECK 1st
-- SELECT DISTINCT PracticeTypeName FROM eVips_chgcv.dbo.vwPracticeLocations -- CHECK 1st (LTRIM(RTRIM(vpl.PracticeTypeName))) AS [Type of Service]
-- SELECT * FROM eVips_chgcv.dbo.vwEntityAssignments WHERE (LTRIM(RTRIM(TableName))) LIKE '%Practice%' AND (LTRIM(RTRIM(EntityName))) LIKE '%MED%IMPA%' -- CHECK 1st
FROM eVips_chgcv.dbo.vwPractices AS vp
	INNER JOIN eVips_chgcv.dbo.vwPracticeLocations AS vpl ON vp.PracticeID = vpl.PracticeID
		LEFT JOIN eVips_chgcv.dbo.vwFacilities AS vf ON vpl.LocationName = vf.FacilityName
			OR vp.PracticeName = vf.FacilityName
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT PracticeID,ClassOrCategory, ServiceTypeName,ServiceCategoryTypeName 
		FROM eVips_chgcv.dbo.vwLocationServices 
		WHERE ServiceTypeName 
		LIKE '%GROUP%SPEC%'
		) -- CONCLUDE ...
		AS vls ON vp.PracticeID = vls.PracticeID -- DEFINE FAC CHAPTER(s) 
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT LocationID,PracticeID,ClassOrCategory, ServiceTypeName,ServiceCategoryTypeName,code1,code2 
		FROM eVips_chgcv.dbo.vwLocationServices 
		WHERE (LTRIM(RTRIM(ServiceTypeName))) LIKE '%PHARM%TYPE%' 
			AND ServiceCategoryTypeName IS NOT NULL 
			AND (LTRIM(RTRIM(ServiceCategoryTypeName))) != ''
			) -- CONCLUDE ...
			AS vlspharmtype ON vp.PracticeID = vlspharmtype.PracticeID --DEFINE PHARM TYPE(s)
				AND vpl.LocationID = vlspharmtype.LocationID -- per YOUNG LADY LAURA email ON 20171221 ... Products (CMC & MEDICAL)  are stored at Location Level. The code below is joining based only ON Practice ID. This should be based ON PracticeID + Location
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT LocationID,PracticeID,ClassOrCategory, ServiceTypeName,ServiceCategoryTypeName,code1,code2 
		FROM eVips_chgcv.dbo.vwLocationServices 
		WHERE (LTRIM(RTRIM(ServiceTypeName))) LIKE '%PHARM%SERV%' 
			AND ServiceCategoryTypeName IS NOT NULL 
			AND (LTRIM(RTRIM(ServiceCategoryTypeName))) != ''
			) -- CONCLUDE ...
			AS vlspharmservice ON vp.PracticeID = vlspharmservice.PracticeID --DEFINE PHARM TYPE(s)
				AND vpl.LocationID = vlspharmservice.LocationID -- per YOUNG LADY LAURA email ON 20171221 ... Products (CMC & MEDICAL)  are stored at Location Level. The code below is joining based only ON Practice ID. This should be based ON PracticeID + Location
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT PracticeID,Code1,Code2,ServiceTypeName,ServiceCategoryTypeName 
		FROM eVips_chgcv.dbo.vwLocationServices 
		WHERE ServiceTypeName LIKE '274%TYPE%SERV%'
		) -- CONCLUDE ...
		AS vlsfocus ON vp.PracticeID = vlsfocus.PracticeID --Alt EFFORT TO DEFINE FAC CHAPTER(s)
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT ProviderID,TableName,EntityCode,EntityName,EntityTypeCode,EntityTypeName 
		FROM eVips_chgcv.dbo.vwEntityAssignments 
		WHERE (LTRIM(RTRIM(ISNULL(TableName,'')))) LIKE '%PRACTI%'
		) -- CONCLUDE ...
		AS vea ON vp.PracticeID = vea.ProviderID
		LEFT JOIN
		( -- INITIATE ...
		SELECT DISTINCT ljvlp.ProductTypeCode,ljvlp.ProductTypeName,ljvlp.PracticeTypeName,ljvlp.PracticeID,ljvlp.LocationID,ljvlp.Archived,ljvlp.StatusTypeName,vlpstype.indirectory,vlpstype.ServiceTypeCode,vlpstype.ServiceTypeName,ljvlp.productname,ljvlp.ProductPanelStatusTypeName,ljvlp.ProductPanelStatusTypeCode,ljvlp.ProviderNumber,ljvlp.Focus,ljvlp.ProductID,ljvlp.LocationTypeName 
		FROM eVips_chgcv.dbo.vwLocationProducts AS ljvlp 
			INNER JOIN evips_chgcv.dbo.vwLocationProductServices AS vlpstype ON ljvlp.LocationProductRecID = vlpstype.LocationProductRecID 
		WHERE ISNULL(ljvlp.Archived,'') IN ('N','') 
			AND (ISNULL(ljvlp.StatusTypeName,'') IN ('ACTIVE','') 
				OR ljvlp.StatusTypeName LIKE '%PARTICIP%')
			AND ISNULL(vlpstype.Archived,'') IN ('N','') 
			) -- CONCLUDE ...
			AS vlp ON vpl.PracticeID = vlp.PracticeID --'YOUNG LADY LAURA GAH ID WHERE p.archived = 'N' AND s.ServiceTypeName = 'HOSPITAL' AND p.focus like '%GAH%'' ON 20171120 see ,(LTRIM(RTRIM(vlp.ServiceTypeName))) AS [vlpSERVICETYPENAME]
				AND vpl.LocationID = vlp.LocationID -- per YOUNG LADY LAURA email ON 20171221 ... Products (CMC & MEDICAL)  are stored at Location Level. The code below is joining based only ON Practice ID. This should be based ON PracticeID + Location
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT LocationID,PracticeID,AccreditationTypeCode,AccreditationTypeName,Notes 
		FROM eVips_chgcv.dbo.vwLocationAccreditations AS vla 
		WHERE ISNULL(vla.Archived,'') IN ('N','') 
		) -- CONCLUDE ...
		AS accredboard ON vpl.LocationID = accredboard.LocationID
			AND vpl.PracticeID = accredboard.PracticeID
		LEFT JOIN #AGERESTRICTION_FAC AS ager ON vpl.LocationID =ager.LocationID
			AND vpl.PracticeID = ager.PracticeID
			AND vlp.ProductID = ager.ProductID
		LEFT JOIN #ACCESSIBILITY AS acc ON vpl.LocationID = acc.LocationID
			-- AND acc.PracticeID = vpl.PracticeID
		LEFT JOIN #HOURS_FAC AS h ON vpl.PracticeID = h.PracticeID
			AND vpl.LocationID = h.LocationID
		LEFT JOIN INFORMATICS.dbo.ZIP_CODES AS zip ON CASE
WHEN SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,1) = '0'
THEN '0'+ SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),2,4)
WHEN SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,1) = '00'
THEN '00'+ SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),3,3)
ELSE  SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,5) 
END = SUBSTRING(LTRIM(RTRIM(zip.ZipCode)),1,5) COLLATE DATABASE_DEFAULT
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT zipcode,city,county,RegionTypeName 
		FROM eVips_chgcv.dbo.vwzipcodes 
		WHERE (LTRIM(RTRIM(ISNULL(county,'')))) LIKE '%SAN%DIEGO%'
		) -- CONCLUDE ...
		AS regionis ON CASE 
		WHEN SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,1) = '0' 
		THEN '0'+ SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),2,4) 
		WHEN SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,1) = '00' 
		THEN '00'+ SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),3,3) 
		ELSE  SUBSTRING(LTRIM(RTRIM(vpl.ZipCode)),1,5) 
		END = CASE 
		WHEN SUBSTRING(LTRIM(RTRIM(regionis.ZipCode)),1,1) = '0' 
		THEN '0'+ SUBSTRING(LTRIM(RTRIM(regionis.ZipCode)),2,4) 
		WHEN SUBSTRING(LTRIM(RTRIM(regionis.ZipCode)),1,1) = '00' 
		THEN '00'+ SUBSTRING(LTRIM(RTRIM(regionis.ZipCode)),3,3) 
		ELSE  SUBSTRING(LTRIM(RTRIM(regionis.ZipCode)),1,5) 
		END
		LEFT JOIN 
		( -- INITIATE ...
		SELECT DISTINCT r.FieldName,r.DisplayName,s.specialtycode,s.specialtyName AS [eVIPS_Specialty],r.Value AS [TIMELYACCESS_Profile] 
		FROM evips_chgcv.dbo.vwReferenceUserFields AS r 
			LEFT JOIN evips_chgcv.dbo.vwSpecialties AS s ON r.ParentRecID  = s.specialtyid
		WHERE r.tablename = 'Specialties' 
			AND r.fieldName = 'Specialty Grouping - Timely Access'
			) -- CONCLUDE ... 
		AS profile ON (LTRIM(RTRIM(ISNULL(vlsfocus.Code1,'')))) = (LTRIM(RTRIM(ISNULL(profile.specialtycode,''))))

		LEFT JOIN #FUTURETERM AS ftm ON CASE
		WHEN vpl.NationalProviderID IS NULL
			AND (LTRIM(RTRIM(vf.FacilityStatus))) LIKE 'ACTIVE%'
			AND (LTRIM(RTRIM(vf.ApplicationStatus))) LIKE 'ACTIVE%'
		THEN LTRIM(RTRIM(ISNULL(vf.NationalProviderID,'')))
		ELSE LTRIM(RTRIM(ISNULL(vpl.NationalProviderID,''))) 
		END =LTRIM(RTRIM(ISNULL(ftm.NationalProviderID,'')))
WHERE 1=1 
	AND vp.Archived IN ('N') --WITH eVIPS LOGICAL BINARY OPTION(s) IN USE •	Must not be archived 
	AND ISNULL(vp.PracticeStatus,'') IN ('ACTIVE','CONTRACTED','NA','') --•	Contract Status must be Active
	AND vpl.Archived IN ('N') --WITH eVIPS LOGICAL BINARY OPTION(s) IN USE •	Must not be archived

UPDATE #INNETWORK_FAC
SET [CountyIs] = LTRIM(RTRIM(ISNULL(addcounty.[County],'Unknown')))
,[County] = LTRIM(RTRIM(ISNULL(addcounty.[County],'Unknown')))
FROM #INNETWORK_FAC AS pdnf
		LEFT JOIN 
		( -- INITIATE ...
		SELECT ' ' AS 'ADD COUNTY FROM "DMHC CA County and ZIP Code Combinations - Revised 3.24.2020.xlsx" : ' 
		,City
		,[State]
		,SUBSTRING(LTRIM(RTRIM(ISNULL(ZipCode,''))),1,5) AS ZIP
		,ZipCode
		,County
		FROM INFORMATICS.dbo.ZIP_CODES -- LEVERAGE: "ZIP_DMHC CA County and ZIP Code Combinations - Revised 3.24.2020.xlsx" AND / OR "TIMELYACCESS_...rar" SERVICE AREA
		WHERE 1=1
			-- AND County LIKE '%SAN%DIEG%'
		GROUP BY City,[State],SUBSTRING(LTRIM(RTRIM(ISNULL(ZipCode,''))),1,5),ZipCode,County
		) -- CONCLUDE ...
		AS addcounty ON pdnf.[Zip Code] = addcounty.ZIP

