DROP TABLE IF EXISTS #INNETWORK_FAC_CCA 
DROP TABLE IF EXISTS #INNETWORK_FAC_CHPIV
DROP TABLE IF EXISTS #INNETWORK_FAC_CSNP 

SELECT DISTINCT inn.*
INTO #INNETWORK_FAC_CHPIV
FROM #INNETWORK_FAC AS inn
	INNER JOIN #chpiv AS mso ON ISNULL(inn.practiceid,'') = ISNULL(mso.practiceid,'')
		AND ISNULL(inn.locationid,'') = ISNULL(mso.locationid,'')

UPDATE #INNETWORK_FAC_CHPIV
SET [Participating Network] = mso.ProductName -- C005: IDENTIFY CHPIV PER MEETING WITH() MS JOHANNA AND MS SANDRA ON 20250219 ... see "Copy of CHPIV_Rosters_Consolidated.xlsx"
,[Name of Network] = 'MSO CHPIV'
FROM #INNETWORK_FAC AS inn
	INNER JOIN #chpiv AS mso ON ISNULL(inn.practiceid,'') = ISNULL(mso.practiceid,'')
		AND ISNULL(inn.locationid,'') = ISNULL(mso.locationid,'')

INSERT INTO #INNETWORK_FAC -- (FIELD(S) IN PLAY,...)
SELECT * 
FROM #INNETWORK_FAC_CHPIV 

SELECT DISTINCT inn.*
INTO #INNETWORK_FAC_CCA
