	INNER JOIN #ccaid AS cca ON ISNULL(inn.practiceid,'') = ISNULL(cca.practiceid,'')
		AND ISNULL(inn.locationid,'') = ISNULL(cca.locationid,'')

UPDATE #INNETWORK_FAC_CCA
SET [Participating Network] = 'CCA'  -- C004: ADD LOB 'CCA' (COVERED CA) GO LIVE SET FOR 01/01/2026
,[Name of Network] = 'Covered CA'

INSERT INTO #INNETWORK_FAC -- (FIELD(S) IN PLAY,...)
SELECT * 
FROM #INNETWORK_FAC_CCA 

SELECT  DISTINCT *
INTO #INNETWORK_FAC_CSNP
FROM #INNETWORK_FAC
