-- ====================================================================
	-- DETERMINE HOW IN NETWORK / 'indirectory' PROV(s) are to be pulled ;WITH SQL07.eVips_chgcv--
-- ====================================================================
--------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
--------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #INNETWORK_PROV -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT  'PROVIDER(s)' AS [NOTE(s)]
,(LTRIM(RTRIM(vpps.InDirectory))) AS [INDIRECTORY]
,(LTRIM(RTRIM(vpd.Archived))) AS [vpdARCHIVED]
,(LTRIM(RTRIM(vpd.PractitionerStatus))) AS [vpdPRACTITIONERSTATUS]
,(LTRIM(RTRIM(vpp.Archived))) AS [vppARCHIVED]
,(LTRIM(RTRIM(vpp.StatusTypeName))) AS [vppSTATUSTYPENAME]
,(LTRIM(RTRIM(vploc.Archived))) AS [vplocARCHIVED]
,vpracloc.locationtypename,(LTRIM(RTRIM(vpracloc.Archived))) AS [vpraclocARCHIVED]
,CAST(NULL AS nvarchar(100)) AS ID -- NPI IFERROR(VLOOKUP()) COL(s)
,REPLACE(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM(vpd.PrefixName))),'[',''),']',''),'&',''),'.',''),' AND ','') AS [PrefixName] -- Exclude period (.)
,REPLACE(REPLACE(REPLACE(REPLACE(REPLACE((LTRIM(RTRIM(vpd.SuffixName))),'[',''),']',''),'&',''),'.',''),' AND ','') AS [SuffixName] -- Exclude period (.)
,(LTRIM(RTRIM(vpd.LastName))) AS [LastName]
,(LTRIM(RTRIM(vpd.FirstName))) AS [FirstName]
,(LTRIM(RTRIM(vpd.MiddleName))) AS [MiddleName]
,SUBSTRING((LTRIM(RTRIM(ISNULL(CONVERT(nvarchar(25),CAST(vpd.BirthDate AS datetime),120),'')))),1,10) AS [DOB] -- yyyy-mm-dd
,vpp.PracticeAs,vpp.ProductTypeCode -- ,(LTRIM(RTRIM(vpp.PracticeAs))) AS [plan_type]
,(LTRIM(RTRIM(vpp.ProductTypeCode))) AS [plan_type]
,(LTRIM(RTRIM(vpp.PracticeAs))) AS [plan_type_fullname]
,(LTRIM(RTRIM(vpp.ProductName))) AS [plan_name]
,(LTRIM(RTRIM(vpp.PractitionerTypeCode))) AS [degree_type]
,CAST(NULL AS nvarchar(5)) AS [committie]
,'All Record Types' AS [PCP Record Type] -- TimelyAccessPCP
,'All Record Types' AS [PCP Extender Record Type] -- TimelyAccessPCP_Extender
,'All Record Types' AS [Specialist Record Type] -- TimelyAccessSPE
,(LTRIM(RTRIM(vpp.PracticeID))) AS [DBAPracticeID]
,(LTRIM(RTRIM(vpp.PracticeName))) AS [DBA]
,LTRIM(RTRIM(vpd.NationalProviderID)) AS NPIis
,CAST(NULL AS nvarchar(25)) AS [CA_License]
,CAST(NULL AS nvarchar(100)) AS [Health Plan ID for Plan-to-Plan Contract]
,(LTRIM(RTRIM(vpd.PractitionerTypeCode))) AS [TypeOfLicensure]
,(LTRIM(RTRIM(vpp.PracticeName))) AS [ASSOCIATION GROUP]
,vpd.PractitionerTypeName -- ,(LTRIM(RTRIM(vpd.PractitionerTypeName))) AS [DEGREE DESCRIPTION]
,CAST(NULL AS nvarchar(100)) AS [DEGREE DESCRIPTION]
,CAST(NULL AS nvarchar(255)) AS [CULTURAL COMPETENCE]
,CASE
WHEN LTRIM(RTRIM(vpp.ProductName)) = 'MEDICAL'
THEN 'CL1'
WHEN LTRIM(RTRIM(vpp.ProductName)) = 'MEDICARE'
THEN 'MCR'
WHEN LTRIM(RTRIM(vpp.ProductName)) = 'CMC'
THEN 'CMC'
ELSE CAST(NULL AS nvarchar(MAX))
END AS [Participating Network]
,CASE
WHEN LTRIM(RTRIM(vpp.ProductName)) = 'MEDICAL'
THEN 'MEDI_CAL'
WHEN LTRIM(RTRIM(vpp.ProductName)) = 'MEDICARE'
THEN 'Communicare_Advantage'
WHEN LTRIM(RTRIM(vpp.ProductName)) = 'CMC'
THEN 'CMC'
ELSE CAST(NULL AS nvarchar(MAX))
END AS [Name of Network]
,CAST(NULL AS nvarchar(100)) AS [HealthPlanID_for_PlanToPlanContract]
,CAST(NULL AS nvarchar(100)) AS [Language] -- see '#LANGUAGEs' FOR FUTURE QUPD(s) SYNTAX
,CAST(NULL AS nvarchar(100)) AS [Language (Other)]
,CAST(NULL AS nvarchar(100)) AS [Language1]
,CAST(NULL AS nvarchar(100)) AS [Language2]
,CAST(NULL AS nvarchar(100)) AS [Language3]
,CAST(NULL AS nvarchar(100)) AS [Language4]
,CAST(NULL AS nvarchar(100)) AS [Language5]
,(LTRIM(RTRIM(h.[Office Hour(s)]))) AS [Office Hour(s)]
-- ,CAST(NULL AS nvarchar(255)) AS [Accessibility] -- ,(LTRIM(RTRIM(address.npi_subpart))) AS [Accessibility] SAMPLE(): 'BASIC ACCESS'
-- ,CAST(NULL AS nvarchar(255)) AS [Accessibility Category(ies)] -- ,(LTRIM(RTRIM(address.userdef_2))) AS [Accessibility Category(ies)] SAMPLE(): 'P, EB, IB, W, R, E'
,acc.[Accessibility] -- HARDCODED LIKE VIPs vwLocationServices
,acc.[Accessibility Category(ies)] -- HARDCODED LIKE VIPs
--,CAST(NULL AS nvarchar(25)) [AGE RESTRICTION]AS  --QUPD / CASE WHEN THEN ELSE END... USE pcp.specialty AND pcp.age_restriction AND pcp.age-restriction2
,ager.[AGE RESTRICTION]
,'NA' AS [Percentage of Time Allocated to Plans Medi-Cal Members] -- Percentage of provider's total work hours spent at clinic.  If unknown,enter "NA."
,'Y' AS [Traditional and/or Safety Net Provider] -- Y/N to specify if provider is Traditional and/or Safety Net Provider
,'N' AS [Specialist Serves as PCP to SPD?] -- Y/N to specify if Specialist Serves as PCP to SPD? 
,'N' AS [Telehealth Provider (Y/N)] -- All fields listed below are required. Required fields MUST be completed or contain a value of "0" of "NA" (Except for "Plan-to-Plan Contract" field)
,(LTRIM(RTRIM(vploc.LineNumber1))) AS [address1]
,(LTRIM(RTRIM(vploc.LineNumber2))) AS [address2]
,(LTRIM(RTRIM(vploc.LineNumber3))) AS [address3]
,CASE
WHEN ((LTRIM(RTRIM(vploc.LineNumber2))) IN ('')
	OR vploc.LineNumber2 IS NULL)
THEN (LTRIM(RTRIM(vploc.LineNumber1)))
ELSE (RTRIM(LTRIM(vploc.LineNumber1)))+' '+(RTRIM(LTRIM(vploc.LineNumber2)))
END AS [Address]
,(LTRIM(RTRIM(vploc.City))) AS [CityIs]
/* ,CASE
WHEN (LTRIM(RTRIM(zip.County))) LIKE 'SD%'
THEN 'SAN DIEGO'
ELSE (LTRIM(RTRIM(zip.County)))
END AS [CountyIs]
,CASE
WHEN (LTRIM(RTRIM(zip.County))) LIKE 'SD%'
THEN 'SAN DIEGO'
ELSE (LTRIM(RTRIM(zip.County)))
END AS [County] */
-- ,LTRIM(RTRIM(ISNULL(addcounty.[County],'Unknown'))) AS [CountyIs]
