,vea.TableName,vea.EntityCode,vea.EntityName,vea.EntityTypeCode,vea.EntityTypeName --ARRIVE AT ENTITY TYPE(s) FROM PROVDIR MEETING ON 20170920 SPECIFICALLY TO ID VSP PROV(s) ... --ProviderID = PractitionerID WHERE (LTRIM(RTRIM(vea.TableName))) LIKE '%Practit%' OR  ProviderID = PracticeID WHERE (LTRIM(RTRIM(vea.TableName))) LIKE '%Practice%'
