DROP TABLE IF EXISTS #CULTURAL -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT u.ProviderID,d.PractitionerID,u.DataSource,u.Value
--,CAST(NULL AS nvarchar(100)) AS [CULTURAL COMPETENCE]
,CASE
WHEN (LTRIM(RTRIM(u.Value))) LIKE '%C%' --OR DATATYPE ???
	AND (LTRIM(RTRIM(u.Value))) LIKE '%H%'
	AND (LTRIM(RTRIM(u.Value))) LIKE '%M%'
THEN 'CHG Language Assistance Program,CHG Ten Commandments Communicating & CHG Disability Language Etiquette,HHS Culturally Competent Care,Medical Groups Culturally Competent Care'
WHEN (LTRIM(RTRIM(u.Value))) LIKE '%C%'
	AND (LTRIM(RTRIM(u.Value))) LIKE '%H%'
THEN 'CHG Language Assistance Program,CHG Ten Commandments Communicating & CHG Disability Language Etiquette,HHS Culturally Competent Care'
WHEN (LTRIM(RTRIM(u.Value))) LIKE '%H%'
	AND (LTRIM(RTRIM(u.Value))) LIKE '%M%'
THEN 'HHS Culturally Competent Care,Medical Groups Culturally Competent Care'
WHEN (LTRIM(RTRIM(u.Value))) LIKE '%C%'
	AND (LTRIM(RTRIM(u.Value))) LIKE '%M%'
THEN 'CHG Language Assistance Program,CHG Ten Commandments Communicating & CHG Disability Language Etiquette,Medical Groups Culturally Competent Care'
WHEN (LTRIM(RTRIM(u.Value))) = 'H'
THEN 'HHS Culturally Competent Care'
WHEN (LTRIM(RTRIM(u.Value))) = 'M'
THEN 'Medical Groups Culturally Competent Care'
WHEN (LTRIM(RTRIM(u.Value))) = 'C'
THEN 'CHG Language Assistance Program,CHG Ten Commandments Communicating & CHG Disability Language Etiquette'
ELSE CAST('NONE' AS nvarchar(255))
END AS [CULTURAL COMPETENCE]
INTO #CULTURAL
-- SELECT * FROM eVips_chgcv.dbo.vwLocationPhones -- CHECK 1st
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
