	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
--------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #OSHPD_FAC -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT vploc.LocationID,vploc.PracticeID,vploc.AddressID,REPLACE((LTRIM(RTRIM(vplic.LicenseNumber))),'-','') AS [OSHPD_ID],REPLACE((LTRIM(RTRIM(vploc.PracticeLegalName))),'-','') AS [HOSP_SYS],(LTRIM(RTRIM(vploc.NationalProviderID))) AS [NPIis]
,vploc.PracticeNationalProviderID,vploc.BillingPayableToName,vploc.LocationName,vplic.PracticeName
INTO #OSHPD_FAC
-- SELECT vplic.LicenseNumber,* -- CHECK 1st
-- SELECT * FROM eVips_chgcv.dbo.vwPracticeLicenses WHERE LicenseTypeName LIKE '%OSHPD%' -- CHECK 1st 
-- SELECT DISTINCT LocationTypeName FROM eVips_chgcv.dbo.vwPracticeLocations -- CHECK 1st
FROM eVips_chgcv.dbo.vwPracticeLocations AS vploc
	INNER JOIN eVips_chgcv.dbo.vwPracticeLicenses AS vplic ON vploc.PracticeID = vplic.PracticeID
		AND vploc.LocationID = vplic.LocationID
		AND vploc.AddressID = vplic.AddressID
WHERE (LTRIM(RTRIM(vploc.LocationTypeName))) LIKE '%PRACTIC%'
	AND ((LTRIM(RTRIM(vplic.LicenseTypeName))) LIKE '%OSHPD%'
			OR vplic.LicenseTypeName IS NULL)
	AND vplic.LicenseNumber IS NOT NULL
	AND (LTRIM(RTRIM(vplic.LicenseNumber))) != ''
	
		-- SELECT * FROM #OSHPD_FAC ORDER BY LocationName







