UPDATE #INNETWORK_FAC
SET [COUNTYIs] = CASE
WHEN LTRIM(RTRIM([Zip Code])) IN ('92010','92011','92081')
THEN 'SAN DIEGO'
ELSE (LTRIM(RTRIM([COUNTYIs])))
END
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT CountyIs,NOcounty,CityIs,StateIs,[Zip Code]
FROM #INNETWORK_FAC
WHERE CountyIs IS NULL

UPDATE #INNETWORK_PROV
SET [COUNTYIs] = CASE
WHEN LTRIM(RTRIM([Zip Code])) IN ('92010','92011','92081')
THEN 'SAN DIEGO'
ELSE (LTRIM(RTRIM([COUNTYIs])))
END
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT CountyIs,NOcounty,CityIs,StateIs,[Zip Code]
FROM #INNETWORK_PROV
WHERE 1=1
	AND CountyIs IS NULL

