-- ===================================================================
	-- CONSOLIDATE FACILITY LANGUAGE(s) FORMERLY 'PROVDIR_JL_Languages_'...sql--
-- ===================================================================
UPDATE #INNETWORK_PROV
SET [Language1] = (LTRIM(RTRIM(qupd.[Language1])))
,[Language2] = (LTRIM(RTRIM(qupd.[Language2])))
,[Language3] = (LTRIM(RTRIM(qupd.[Language3])))
,[Language4] = (LTRIM(RTRIM(qupd.[Language4])))
,[Language5] = (LTRIM(RTRIM(qupd.[Language5])))
,[FINALlang] = SUBSTRING(STUFF(ISNULL(', ' +(LTRIM(RTRIM(qupd.Language1))),'') + 
ISNULL(', ' +(LTRIM(RTRIM(qupd.Language2))),'') + 
ISNULL(', ' +(LTRIM(RTRIM(qupd.Language3))),'') + 
ISNULL(', ' +(LTRIM(RTRIM(qupd.Language4))),'') + 
ISNULL(', ' +(LTRIM(RTRIM(qupd.Language5))),''),1,2,''),1,255) --REMOVE comma (',') FROM 1st STATEMENT() SIR EVAN ON 20160721 'STUFF'([SOURCE STRING],[WHERE TO start IN STRING],[HOW MANY CHAR() TO REPLACE],[WHAT TO ADD TO THE STRING])
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT * FROM #LANGUAGEs -- CHECK 1st
-- SELECT DISTINCT CountyIs,NOcounty,CityIs,StateIs,[Zip Code]
FROM #INNETWORK_PROV AS inet
	INNER JOIN #LANGUAGEs AS qupd ON inet.NPIis = qupd.NPIis
		AND inet.lookup_key = qupd.lookup_key
--WHERE inet.[FINALlang] IS NULL







-- ===================================================================
	-- LANGUAGE(s) FOR FAC(s)--
-- ===================================================================
------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #SiteLanguages -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT *
,DENSE_RANK() OVER (PARTITION BY [lookup_key] ORDER BY [FINALlang] ASC) AS [RANKis]
INTO #SiteLanguages
-- SELECT TOP 100 *  -- CHECK 1st
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM 
( --INITIATE ...
SELECT DISTINCT vll.PracticeID,vll.LocationID,vll.LocationID AS 'lookup_key'
,(LTRIM(RTRIM(vll.LanguageName))) AS FINALlang
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM eVips_chgcv.dbo.vwLocationLanguages AS vll
UNION --VERTICAL() STACK DISTINCT()
SELECT DISTINCT np.PracticeID,np.LocationID,(LTRIM(RTRIM(np.LocationID))) AS 'lookup_key'
,(LTRIM(RTRIM(np.Language1))) AS FINALlang -- IGNORE AS THIS IS THE DEFAULT "English" RECORD
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM #INNETWORK_PROV AS np --PROV(s)
UNION --VERTICAL() STACK DISTINCT()
SELECT DISTINCT np.PracticeID,np.LocationID,np.LocationID AS 'lookup_key'
,(LTRIM(RTRIM(np.Language2))) COLLATE DATABASE_DEFAULT AS FINALlang
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM #INNETWORK_PROV AS np --PROV(s)
UNION --VERTICAL() STACK DISTINCT()
SELECT DISTINCT np.PracticeID,np.LocationID,np.LocationID  AS 'lookup_key'
,(LTRIM(RTRIM(np.Language3))) AS FINALlang
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM #INNETWORK_PROV AS np --PROV(s)UNION ALL --VERTICAL() w UNION ALL()  - ROW(s) --STACK
UNION --VERTICAL() STACK DISTINCT()
SELECT DISTINCT np.PracticeID,np.LocationID,np.LocationID  AS 'lookup_key'
,(LTRIM(RTRIM(np.Language4))) AS FINALlang
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM #INNETWORK_PROV AS np --PROV(s)UNION ALL --VERTICAL() w UNION ALL()  - ROW(s) --STACK
UNION --VERTICAL() STACK DISTINCT()
SELECT DISTINCT np.PracticeID,np.LocationID,np.LocationID AS 'lookup_key'
,(LTRIM(RTRIM(np.Language5))) AS FINALlang
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM #INNETWORK_PROV AS np --PROV(s)
) -- CONCLUDE ...
AS aliasfaclang
WHERE (LTRIM(RTRIM(ISNULL(aliasfaclang.FINALlang,'')))) != '' -- ONLY VAL(s)!!!

