			OR (LTRIM(RTRIM(plan_type))) NOT IN ('COMMUNITY CLINIC')) --see 'TimelyAccessCLINIC' --,(LTRIM(RTRIM(vp.PracticeTypeName))) AS [plan_type]
		-- AND (LTRIM(RTRIM([Type of Service]))) IN ('AMB',' ASC','CBAS','DLC','DME','DXC','HDM','HHC','IHSS','NF','RCF','SNF','URC','CL','HPM','HSPC','HOSPICE')) ,'Free Standing - Primary and/or Specialty Care' AS [Type of Service] ??? per Network Adequacy REVIEW WITH TEAM ON 20170302...ADD HOSPICE facility(-ies) per SC ON 20161012 Walter/Maryanne/Kelly Question 13 is asking for the display in printed and online for 2 new sections (hospice & inpatient rehabilitation).  I will send specs ON hospice. 	--,(LTRIM(RTRIM(vpl.PracticeTypeName)))AS [Type of Service]
		AND LTRIM(RTRIM(ISNULL([INDIRECTORY],''))) LIKE @INDIR --SET @INDIR ='Y'--REMOVE FILTER FOR JOSEPH / TIMELYACCESS HBP(s)... '%' OR 'Y'  OR 'N'--SUBSTRING((LTRIM(RTRIM(cert_provider.in_directory))),1,1) LIKE @INDIR --see 'LTRIM(RTRIM(mcred.retrieve_list)) LIKE '%CN%V%'
		) -- CONCLUDE ... BASE FACILITY(-ies). WIHOUT '%FAC%'

	OR 
	( -- INITIATE ...
	[vplLOCATIONTYPENAME] LIKE '%PRACTICE%' -- per YOUNG LADY LAURA email ON 20171221 ... 1.	For Facilities we need to make sure that we are excluding DBA product location records. Please add a condition to only include Locations that begin with the word “Practice”: vwLocationProducts.LocationTypeName like 'PRACTICE%'
		AND LTRIM(RTRIM(ISNULL([INDIRECTORY],''))) LIKE @INDIR --SET @INDIR ='Y'--REMOVE FILTER FOR JOSEPH / TIMELYACCESS HBP(s)... '%' OR 'Y'  OR 'N'--SUBSTRING((LTRIM(RTRIM(cert_provider.in_directory))),1,1) LIKE @INDIR --see 'LTRIM(RTRIM(mcred.retrieve_list)) LIKE '%CN%V%'
