UPDATE INFORMATICS.dbo.TimelyAccessPCP
SET [DEGREE DESCRIPTION] = CASE
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'IMF%'
THEN 'MARRIAGE & FAMILY THERAPIST INTERN'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'LCS%'
THEN 'LICENSED CLINICAL SOCIAL WORKER'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'LEP%'
THEN 'LICENSED EDUCATIONAL PSYCHOLOGIST'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'MFC%'
THEN 'MARRIAGE & FAMILY COUNSELOR'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'MFT%'
THEN 'MARRIAGE & FAMILY THERAPIST'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'PSB%'
THEN 'REGISTERED PSYCHOLOGIST ASSISTANT'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'PSY%'
THEN 'PSYCHOLOGIST'
WHEN (LTRIM(RTRIM(CA_License))) LIKE 'RP%'
THEN 'REGISTERED PSYCHOLOGIST'
ELSE CAST(NULL AS nvarchar(100)) --AS [DEGREE DESCRIPTION]
END
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.TimelyAccessPCP AS ta
WHERE [DEGREE DESCRIPTION] IS NULL
	OR LTRIM(RTRIM([DEGREE DESCRIPTION])) = ''

