	-- Generate ref table for PCP Extender SUPER(s)--
	-- POST [TimelyAccess...] PROV(s) TABLE(s)--
-- ===================================================================
--------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
--------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #NP -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT '[ProviderRepository] ERROR REPORT ADD ... see [GetErrorsProviderRelationships]' AS [NOTE(S)],PractitionerStatus,CoveringPractitionerID,PracticeCoveringTypeName,(LTRIM(RTRIM(CAST(vpcp.LastName AS nvarchar(255))))) AS PANPlnm
,(LTRIM(RTRIM(CAST(vpcp.FirstName AS nvarchar(255))))) AS PANPfnm
,(LTRIM(RTRIM(vpp.ProductTypeCode))) AS [PANPpt]
,(LTRIM(RTRIM(vpcp.PractitionerID))) AS PANPlkup
,(LTRIM(RTRIM(vpd.NationalProviderID))) AS PANPnpi
,(LTRIM(RTRIM(CAST(vpcp.CoveringPractitionerID AS nvarchar(25))))) AS SUPERlkup --'LOOKUP KEY!!!'
,(LTRIM(RTRIM(CAST(vpcp.CoveringPhysicianName AS nvarchar(255))))) AS SUPERNM
,CAST(NULL AS nvarchar(MAX)) SUPERnpi
,CAST(NULL AS nvarchar(MAX)) AS SUPERspe
,CAST(NULL AS nvarchar(MAX)) AS SUPERspeOTH
INTO #NP
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st',PracticeAs,ProductTypeCode FROM eVips_chgcv.dbo.vwPractitionerProducts
FROM eVips_chgcv.dbo.vwPractitionerDemographics AS vpd
	INNER JOIN eVips_chgcv.dbo.vwPractitionerCoveringPhysicians AS vpcp ON vpd.PractitionerID = vpcp.PractitionerID -- THE PA NPMP
	INNER JOIN eVips_chgcv.dbo.vwPractitionerProductSpecialties AS vpps ON vpd.PractitionerID = vpps.PractitionerID
	INNER JOIN eVips_chgcv.dbo.vwPractitionerProducts AS vpp ON vpd.PractitionerID = vpp.PractitionerID
		AND vpps.ProductID = vpp.ProductID
-- WHERE (LTRIM(RTRIM(vpp.ProductTypeCode))) LIKE '%NPMP%' --Cert_provider.plan_type has one of the following values: PCP,SPE,AHP,and HBP or starts with NPMP --,(LTRIM(RTRIM(vpp.ProductTypeCode))) AS [plan_type]
-- WHERE vpd.NationalProviderID IN ('1134232259','1184954455') -- MS SANDRASAMPLE(S)')
-- WHERE vpcp.CoveringPractitionerID In ('4354608','4371811') -- MS SANDRASAMPLE(S)')
-- WHERE LTRIM(RTRIM(vpd.NationalProviderID)) IN ('1295980977','1093180432','1932622156','1780024588') --TIMLEY ACCESS TEST CASE(s)
WHERE (LTRIM(RTRIM(vpp.ProductTypeCode))) LIKE '%NPMP%' --Cert_provider.plan_type has one of the following values: PCP,SPE,AHP,and HBP or starts with NPMP --,(LTRIM(RTRIM(vpp.ProductTypeCode))) AS [plan_type]
	AND (LTRIM(RTRIM(vpcp.PracticeCoveringTypeName))) LIKE '%SUP%' -- SUPERVISING PCP
	AND ISNULL(CoveringPractitionerID,'') != '' -- NO NOT NEGATIVE <> != IS NOT NULL -- PHENOMENON FOUND IN TIMELYACCESS MEETING ON 20180313
	AND (LTRIM(RTRIM(ISNULL(vpd.Archived,'')))) IN ('N')
	AND (LTRIM(RTRIM(ISNULL(vpcp.Archived,'')))) IN ('N')
	AND (LTRIM(RTRIM(ISNULL(vpps.Archived,'')))) IN ('N')
	AND (LTRIM(RTRIM(ISNULL(vpp.Archived,'')))) IN ('N')

		-- SELECT * FROM #NP

UPDATE #NP
SET SUPERnpi = (LTRIM(RTRIM(ISNULL(vpd.NationalProviderID,''))))
FROM #NP AS np
	INNER JOIN eVips_chgcv.dbo.vwPractitionerDemographics AS vpd ON np.SUPERlkup = vpd.PractitionerID

UPDATE #NP
SET SUPERspe = pcp.Specialty
,SUPERspeOTH = pcp.[Specialty (Other)]
FROM #NP AS np
	INNER JOIN INFORMATICS.dbo.TimelyAccessPCP AS pcp ON (LTRIM(RTRIM(ISNULL(np.SUPERlkup,'')))) COLLATE DATABASE_DEFAULT = (LTRIM(RTRIM(ISNULL(pcp.lookup_key,'')))) COLLATE DATABASE_DEFAULT

UPDATE #NP
SET SUPERspe = pcp.Specialty
,SUPERspeOTH = pcp.[Specialty (Other)]
FROM #NP AS np
	INNER JOIN INFORMATICS.dbo.TimelyAccessPCP AS pcp ON (LTRIM(RTRIM(np.PANPlnm)))+' '+(LTRIM(RTRIM(np.PANPfnm))) COLLATE DATABASE_DEFAULT = (LTRIM(RTRIM(np.SUPERNM))) COLLATE DATABASE_DEFAULT -- EXTRAORDINARY JOIN TO FIT NEEDS ...
WHERE SUPERnpi IS NULL

UPDATE #NP
SET SUPERspe = 'FAM' --DFLT
,SUPERspeOTH = CAST(NULL AS nvarchar(100)) --DFLT
FROM #NP AS np

UPDATE INFORMATICS.dbo.TimelyAccessPCP_Extender
SET [NPI of Supervising PCP] = np.SUPERnpi
,[Supervising PCP Specialty] = np.SUPERspe
,[Supervising PCP Specialty (Other)] = np.SUPERspeOTH
FROM INFORMATICS.dbo.TimelyAccessPCP_Extender AS pcpe
	INNER JOIN #NP AS np ON (LTRIM(RTRIM(pcpe.lookup_key))) COLLATE DATABASE_DEFAULT = (LTRIM(RTRIM(np.PANPlkup))) COLLATE DATABASE_DEFAULT

UPDATE INFORMATICS.dbo.TimelyAccessPCP_Extender
SET [NPI of Supervising PCP] = '9999999999' --DFLT
,[Supervising PCP Specialty] = 'FAM' --DFLT
,[Supervising PCP Specialty (Other)] = CAST(NULL AS nvarchar(100)) -- DFLT
FROM INFORMATICS.dbo.TimelyAccessPCP_Extender AS pcpe
WHERE ISNULL([NPI of Supervising PCP],'') = ''

DELETE 
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT NPIis -- CHECK 1st
FROM INFORMATICS.dbo.TimelyAccessPCP_Extender
WHERE [NPI of Supervising PCP] = '9999999999' --DFLT







