	INNER JOIN #NPMPMAX AS npmp ON pcp.PCPNPI COLLATE DATABASE_DEFAULT = npmp.PCPNPI COLLATE DATABASE_DEFAULT -- [NPI of Supervising PCP]
		AND (LTRIM(RTRIM(npmp.[Name of Network]))) COLLATE DATABASE_DEFAULT = (LTRIM(RTRIM(pcp.[Name of Network]))) COLLATE DATABASE_DEFAULT --LOB
	
UPDATE #AcceptingMAX
SET TOTALacceptingMAX = PCPmax+(NPNMadd*NPMP)
-- SELECT PCPmax+(NPNMadd*NPMP),* -- CHECK 1st
FROM #AcceptingMAX
	
