FROM INFORMATICS.dbo.TimelyAccessPCP AS pcp ----------------WHERE NPIis = '1275630618' OR LastName LIKE '%NATH%'
	INNER JOIN #AcceptingMAX AS npmp ON pcp.NPIis COLLATE DATABASE_DEFAULT = npmp.PCPNPI COLLATE DATABASE_DEFAULT -- [NPI of Supervising PCP]
