-- ====================================================================
	-- PROVDIR() SETUP [TABLE](s)--
-- ====================================================================
--------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
--------------------------------------------------------------------------------------------------------------------
/* TRUNCATE TABLE
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
TABLENAME */

DELETE 
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.PROVDIR_PCP

DROP TABLE IF EXISTS #PROVDIR_PCP -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT pcp.NPIis,pcp.[Participating Network]
,CAST(NULL AS datetime) [WHEN_PROVIDER_ADDED]
,(LTRIM(RTRIM(pcp.Specialty))) AS [Specialty]  --THE CODE...
,(LTRIM(RTRIM(pcp.[Specialty Description]))) AS SPEC --THE DESCR...
,pcp.CityIs,pcp.[Zip Code],pcp.REGION
,pcp.[INDIRECTORY],pcp.LastName,pcp.FirstName,pcp.[MiddleName],pcp.[PrefixName],pcp.[SuffixName],pcp.[DOB]
,pcp.TypeOfLicensure
,SUBSTRING(REPLACE((LTRIM(RTRIM(pcp.LastName))),'.','')+', '+REPLACE((LTRIM(RTRIM(pcp.FirstName))),'.','')+', '+(LTRIM(RTRIM(pcp.TypeOfLicensure))),1,255) AS INDEXNM
,SUBSTRING(REPLACE((LTRIM(RTRIM(pcp.LastName))),'.','')+', '+REPLACE((LTRIM(RTRIM(pcp.FirstName))),'.','')+' '+(LTRIM(RTRIM(pcp.TypeOfLicensure)))+' - ID# '+CASE
WHEN pcp.provider_no IS NULL
THEN ' '
ELSE (LTRIM(RTRIM(pcp.provider_no)))
END,1,255) AS PROVNM
--,(LTRIM(RTRIM(pcp.LastName)))+', '+(LTRIM(RTRIM(pcp.FirstName)))+' '+(LTRIM(RTRIM(pcp.TypeOfLicensure)))+' - ID# '+(LTRIM(RTRIM(pcp.provider_no))) AS PROVNM
,pcp.[Clinic Name] -- SITE aka SERVICELOCATION
,pcp.[DBAPracticeID],pcp.[DBA],pcp.Address1,pcp.Address2,pcp.Address
,(LTRIM(RTRIM(pcp.CityIs)))+', '+(LTRIM(RTRIM(pcp.StateIs)))+' '+(LTRIM(RTRIM(pcp.[Zip Code]))) AS CSZ
,(LTRIM(RTRIM(pcp.[Zip Code]))) AS ZIP
,'('+SUBSTRING(LTRIM(RTRIM(pcp.[Telephone Number])),1,3)+') '+SUBSTRING(LTRIM(RTRIM(pcp.[Telephone Number])),5,3)+'-'+SUBSTRING(LTRIM(RTRIM(pcp.[Telephone Number])),9,4) AS [Telephone Number]
----------------,pcp.[Telephone Number]
,(LTRIM(RTRIM(pcp.LocationID))) AS [Clinic QNXT provid] -- -Per S. Coleman email ON 20171229 '...Site code should be eVIPs unique Location ID ...'
-- ,[Clinic QNXT provid]
,pcp.CA_License
,CASE
WHEN (LTRIM(RTRIM(pcp.[BoardCertified(Y/N)]))) = 'Y'
THEN 'Yes'
ELSE 'Not Applicable'
END AS [BOARD CERTIFIED]
,CASE
WHEN (LTRIM(RTRIM(pcp.[Accepting All Medi-Cal Member Populations]))) = 'Y'
THEN 'Yes'
ELSE 'No'
END AS [ACCEPTING NEW PATIENTS]
,CASE
WHEN pcp.[Office Hour(s)] IS NULL
THEN 'MON-FRI 8AM-5PM' --DFLT VAL()
ELSE (LTRIM(RTRIM(pcp.[Office Hour(s)]))) 
END AS [Office Hour(s)]
,'Yes' AS [ACCESS BY PUBLIC TRANSPORTATION]
,pcp.Accessibility,pcp.[Accessibility Category(ies)]
,pcp. [AGE RESTRICTION]
,SUBSTRING((LTRIM(RTRIM(ISNULL([FINALlang],'')))),1,255) AS [FINALlang] -- see #LANGUAGEs AS qupd
,Language1,Language2,Language3,Language4,Language5
,CAST(NULL AS nvarchar(125)) AS FINALhosp
,CAST(NULL AS nvarchar(25)) AS HOSP1,CAST(NULL AS nvarchar(25)) AS HOSP2,CAST(NULL AS nvarchar(25)) AS HOSP3,CAST(NULL AS nvarchar(25)) AS HOSP4,CAST(NULL AS nvarchar(25)) AS HOSP5  --QUPD / CASE WHEN THEN ELSE END... USE pcp.HOSPabbrev
,CAST(NULL AS nvarchar(255)) AS FINALhosp_FULL_NAME
,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME1,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME2,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME3,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME4,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME5  --QUPD / CASE WHEN THEN ELSE END... USE pcp.HOSPabbrev
,DefineOTH_SPE,pcp.plan_type,pcp.[Provider Gender]
,[ASSOCIATION GROUP]
,[DEGREE DESCRIPTION]
,[CULTURAL COMPETENCE]
----------------,status_code --CAPTURE 'D' & OR 'S' (PER DIEM's & OR CLINIC SPECIALIST)
,pcp.[DSflag]
,@footnotedt+LTRIM(RTRIM(CASE 
WHEN DATEPART(WEEKDAY,@when) = 1 --SUNDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+5,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 2 --MONDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+4,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 3 --TUESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+3,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 4 --WEDNESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+2,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 5 --THURSDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+1,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 7 --SATURDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+6,101) AS nvarchar(10)) -- mm/dd/yyyy
ELSE CAST(CONVERT(varchar,CAST(@when AS datetime)+0,101) AS nvarchar(10)) -- mm/dd/yyyy
END)) AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
-- ,@footnotedt AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
,pcp.[AREA_of_PRACTICE]
,CAST(NULL AS nvarchar(255)) AS [CHAPTER_COUNT],CAST('Primary Care Physician' AS nvarchar(255)) AS [CHAPTER_NAME]
,'PRIMARY CARE' AS [PROVIDER_TYPE]
-- ,[PROVIDER_TYPEdescr] AS [PROVIDER_TYPE]
,pcp.provider_no
,pcp.[ACCREDITATION] -- ADD per MS. K Callies ON 20170323
,pcp.[ACCREDITATION_BY] -- ADD per MS. K Callies ON 20170323
,pcp.lookup_key
,pcp.[URL_WEBSITE]
,pcp.[TTY] AS [AFTERHOURS_PHONE]
,pcp.[FAXnumber],pcp.SpecialtyTypeName,pcp.[EMAILis]
,[CCSPaneledProvider] -- ADD TO THE SIX (6) PROVIDER PROVDIR_... [TABLE(S)]
,[MedicaidMedicareFlag]
,[MMF]
,[FUTURE_TERM]
,TGI_INDICATOR
,[Telehealth_Indicator]
,[COUNTY] -- C007: APPLICABLE TO PROVIDERS ONLY!!! ADD - ON PER EMAIL FROM MS JOHANNA BASED UPON DHCS FINDING (LEVERAGE: APL 25-014 AND OR "PROVDIR Telehealth Indicator evips location .msg")
INTO #PROVDIR_PCP
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.TimelyAccessPCP AS pcp
WHERE 1=1
	AND [SiteName] NOT LIKE 'VSP%' 
	AND vppSTATUSTYPENAME NOT LIKE '%PER%DIEM%' -- NO NOT NEGATIVE <> != ADDED PER CONVERSATION WITH() MS SANDRA (VIA CALL) ON 20230725 TO ADDRES D-SNP 2024 PROVIDER DIRECTORY REGULATORY REQUIREMENTS see "PROVDIR CA DSNP PDCY2024 05.15.2023- LA.DOCX" ... APPLICABLE TO [PCP](S) ONLY !!! EXCLUSION OF locations where a provider may practice only occasionally

