UPDATE INFORMATICS.dbo.PROVDIR_PCP
SET FINALhosp_FULL_NAME = CASE
WHEN HOSP1 IS NULL
	AND HOSP_FULL_NAME2 IS NULL
	AND HOSP_FULL_NAME3 IS NULL
	AND HOSP_FULL_NAME4 IS NULL
	AND HOSP_FULL_NAME5 IS NULL
THEN 'NONE'
WHEN HOSP1 IS NOT NULL
	AND HOSP_FULL_NAME2 IS NULL
	AND HOSP_FULL_NAME3 IS NULL
	AND HOSP_FULL_NAME4 IS NULL
	AND HOSP_FULL_NAME5 IS NULL
THEN (LTRIM(RTRIM(HOSP_FULL_NAME1)))
WHEN HOSP1 IS NOT NULL
	AND HOSP_FULL_NAME2 IS NOT NULL
	AND HOSP_FULL_NAME3 IS NULL
	AND HOSP_FULL_NAME4 IS NULL
	AND HOSP_FULL_NAME5 IS NULL
THEN (LTRIM(RTRIM(HOSP_FULL_NAME1)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME2)))
WHEN HOSP1 IS NOT NULL
	AND HOSP_FULL_NAME2 IS NOT NULL
	AND HOSP_FULL_NAME3 IS NOT NULL
	AND HOSP_FULL_NAME4 IS NULL
	AND HOSP_FULL_NAME5 IS NULL
THEN (LTRIM(RTRIM(HOSP_FULL_NAME1)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME2)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME3)))
WHEN HOSP1 IS NOT NULL
	AND HOSP_FULL_NAME2 IS NOT NULL
	AND HOSP_FULL_NAME3 IS NOT NULL
	AND HOSP_FULL_NAME4 IS NOT NULL
	AND HOSP_FULL_NAME5 IS NULL
THEN (LTRIM(RTRIM(HOSP_FULL_NAME1)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME2)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME3)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME4)))
ELSE (LTRIM(RTRIM(HOSP_FULL_NAME1)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME2)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME3)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME4)))+', '+(LTRIM(RTRIM(HOSP_FULL_NAME5)))
END
