	-- DEFINE CHAPTER COUNT(): 
------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #COUNT_SPE -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT [Participating Network]
,CASE
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(PROVNM)))))=6
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),1,3)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),4,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(PROVNM)))))=5
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),1,2)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),3,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(PROVNM)))))=4
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),1,1)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),2,3)
ELSE CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)) 
END AS [UNIQUErecords]
INTO #COUNT_SPE
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.PROVDIR_SPE
GROUP BY [Participating Network]

		-- 'You will find ## Providers to choose from in this section.'
		-- 'You will find ## Facilities / Centers to choose from in this section.'

UPDATE INFORMATICS.dbo.PROVDIR_SPE
SET [CHAPTER_COUNT] = SUBSTRING('You will find '+[UNIQUErecords]+' Providers to choose from in this section.',1,255)
FROM INFORMATICS.dbo.PROVDIR_SPE AS pdir
	INNER JOIN #COUNT_SPE AS cp ON pdir.[Participating Network] = cp.[Participating Network]

					-- SELECT * FROM INFORMATICS.dbo.PROVDIR_SPE WHERE NPIis = '1043310030'







--------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
--------------------------------------------------------------------------------------------------------------------
/* TRUNCATE TABLE
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
TABLENAME */

DELETE 
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.PROVDIR_MH

DROP TABLE IF EXISTS #PROVDIR_MH -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT spe.NPIis,spe.[Participating Network] COLLATE DATABASE_DEFAULT AS [Participating Network]
,CAST(NULL AS datetime) AS [WHEN_PROVIDER_ADDED]
,(LTRIM(RTRIM(spe.Specialty))) AS [Specialty]  --THE CODE...
,(LTRIM(RTRIM(spe.[Specialty Description]))) AS SPEC --THE DESCR...
,spe.CityIs,spe.[Zip Code]
,spe.REGION
,spe.[INDIRECTORY],spe.LastName,spe.FirstName,spe.[MiddleName],spe.[PrefixName],spe.[SuffixName],spe.[DOB]
,spe.TypeOfLicensure
,SUBSTRING(REPLACE((LTRIM(RTRIM(spe.LastName))),'.','')+', '+REPLACE((LTRIM(RTRIM(spe.FirstName))),'.','')+', '+(LTRIM(RTRIM(spe.TypeOfLicensure))),1,255) AS INDEXNM
,SUBSTRING(REPLACE((LTRIM(RTRIM(spe.LastName))),'.','')+', '+REPLACE((LTRIM(RTRIM(spe.FirstName))),'.','')+' '+(LTRIM(RTRIM(spe.TypeOfLicensure)))+' - ID# '+CASE
WHEN spe.provider_no IS NULL
THEN ' '
ELSE (LTRIM(RTRIM(spe.provider_no)))
END,1,255) AS PROVNM
--,(LTRIM(RTRIM(spe.LastName)))+', '+(LTRIM(RTRIM(spe.FirstName)))+' '+(LTRIM(RTRIM(spe.TypeOfLicensure)))+' - ID# '+(LTRIM(RTRIM(spe.provider_no))) AS PROVNM
,spe.[Clinic Name] -- SITE aka SERVICELOCATION
,spe.[DBAPracticeID],spe.[DBA],spe.Address1,spe.Address2,spe.Address
,(LTRIM(RTRIM(spe.CityIs)))+', '+(LTRIM(RTRIM(spe.StateIs)))+' '+(LTRIM(RTRIM(spe.[Zip Code]))) AS CSZ
,(LTRIM(RTRIM(spe.[Zip Code]))) AS ZIP
,'('+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),1,3)+') '+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),5,3)+'-'+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),9,4) AS [Telephone Number]
----------------,spe.[Telephone Number]
,(LTRIM(RTRIM(spe.LocationID))) AS [Clinic QNXT provid] -- -Per S. Coleman email ON 20171229 '...Site code should be eVIPs unique Location ID ...'
-- ,[Clinic QNXT provid]
,spe.CA_License
,CASE
WHEN (LTRIM(RTRIM(spe.[BoardCertified(Y/N)]))) = 'Y'
THEN 'Yes'
ELSE 'Not Applicable'
END AS [BOARD CERTIFIED]
,CASE
WHEN (LTRIM(RTRIM(spe.[Accepting New Medi-Cal Members/ Referrals]))) = 'Y'
THEN 'Yes'
ELSE 'No'
END AS [ACCEPTING NEW PATIENTS]
,CASE
WHEN spe.[Office Hour(s)] IS NULL
THEN 'MON-FRI 8AM-5PM'
ELSE (LTRIM(RTRIM(spe.[Office Hour(s)]))) 
END AS [Office Hour(s)]
,'Yes' AS [ACCESS BY PUBLIC TRANSPORTATION]
,spe.Accessibility,spe.[Accessibility Category(ies)]
,spe.[AGE RESTRICTION]
,SUBSTRING((LTRIM(RTRIM(ISNULL([FINALlang],'')))),1,255) AS [FINALlang] -- see #LANGUAGEs AS qupd
,Language1,Language2,Language3,Language4,Language5
,CAST(NULL AS nvarchar(125)) AS FINALhosp
,CAST(NULL AS nvarchar(25)) AS HOSP1,CAST(NULL AS nvarchar(25)) AS HOSP2,CAST(NULL AS nvarchar(25)) AS HOSP3,CAST(NULL AS nvarchar(25)) AS HOSP4,CAST(NULL AS nvarchar(25)) AS HOSP5  --QUPD / CASE WHEN THEN ELSE END... USE pcp.HOSPabbrev
,CAST(NULL AS nvarchar(255)) AS FINALhosp_FULL_NAME
,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME1,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME2,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME3,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME4,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME5  --QUPD / CASE WHEN THEN ELSE END... USE pcp.HOSPabbrev
,DefineOTH_SPE,spe.plan_type,spe.[Provider Gender]
,[ASSOCIATION GROUP]
,[DEGREE DESCRIPTION]
,[CULTURAL COMPETENCE]
----------------,status_code --CAPTURE 'D' & OR 'S' (PER DIEM's & OR CLINIC SPECIALIST)
,spe.[DSflag]
,@footnotedt+LTRIM(RTRIM(CASE 
WHEN DATEPART(WEEKDAY,@when) = 1 --SUNDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+5,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 2 --MONDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+4,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 3 --TUESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+3,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 4 --WEDNESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+2,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 5 --THURSDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+1,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 7 --SATURDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+6,101) AS nvarchar(10)) -- mm/dd/yyyy
ELSE CAST(CONVERT(varchar,CAST(@when AS datetime)+0,101) AS nvarchar(10)) -- mm/dd/yyyy
END)) AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
-- ,@footnotedt AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
,spe.[AREA_of_PRACTICE]
,CAST(NULL AS nvarchar(255)) AS [CHAPTER_COUNT],CAST('Mental Health Providers' AS nvarchar(255)) AS [CHAPTER_NAME]
,CASE
WHEN [PROVIDER_TYPEdescr] LIKE '%AHP%'
THEN 'Allied Health Practitioner' 
WHEN [PROVIDER_TYPEdescr] LIKE '%HBP%'
THEN 'Hospital Based Provider' 
WHEN [PROVIDER_TYPEdescr] LIKE '%NP%'
THEN 'Non Physician Medical Practitioner' 
WHEN [PROVIDER_TYPEdescr] LIKE '%SPE%'
THEN 'Specialist' 
ELSE 'Specialist' 
END AS [PROVIDER_TYPE]
-- ,[PROVIDER_TYPEdescr] AS [PROVIDER_TYPE]
,spe.provider_no
,spe.[ACCREDITATION] -- ADD per MS. K Callies ON 20170323
,spe.[ACCREDITATION_BY] -- ADD per MS. K Callies ON 20170323
,spe.lookup_key
,spe.[URL_WEBSITE]
,spe.[TTY] AS [AFTERHOURS_PHONE]
