,[COUNTY] -- C007: APPLICABLE TO PROVIDERS ONLY!!! ADD - ON PER EMAIL FROM MS JOHANNA BASED UPON DHCS FINDING (LEVERAGE: APL 25-014 AND OR "PROVDIR Telehealth Indicator evips location .msg")
INTO #PROVDIR_MH
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT TypeOfLicensure FROM INFORMATICS.dbo.TimelyAccessSPE ORDER BY TypeOfLicensure -- CHECK 1st
-- SELECT DISTINCT DefineOTH_SPE FROM INFORMATICS.dbo.TimelyAccessSPE ORDER BY DefineOTH_SPE -- CHECK 1st
