	-- DEFINE CHAPTER COUNT(): 
------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #COUNT_NPMP -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT [Participating Network]
,CASE
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(PROVNM)))))=6
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),1,3)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),4,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(PROVNM)))))=5
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),1,2)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),3,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(PROVNM)))))=4
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),1,1)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)))),2,3)
ELSE CAST(COUNT(DISTINCT(PROVNM)) AS nvarchar(25)) 
END AS [UNIQUErecords]
INTO #COUNT_NPMP
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.PROVDIR_NPMP
GROUP BY [Participating Network]

		-- 'You will find ## Providers to choose from in this section.'
		-- 'You will find ## Facilities / Centers to choose from in this section.'

UPDATE INFORMATICS.dbo.PROVDIR_NPMP
SET [CHAPTER_COUNT] = SUBSTRING('You will find '+[UNIQUErecords]+' Providers to choose from in this section.',1,255)
FROM INFORMATICS.dbo.PROVDIR_NPMP AS pdir
	INNER JOIN #COUNT_NPMP AS cp ON pdir.[Participating Network] = cp.[Participating Network]

		-- SELECT * FROM INFORMATICS.dbo.TimelyAccessSPE WHERE LastName LIKE '%VERBEC%' AND FirstName LIKE '%MAR%'
		-- SELECT * FROM INFORMATICS.dbo.PROVDIR_NPMP WHERE LastName LIKE '%VERBEC%' AND FirstName LIKE '%MAR%'







------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS INFORMATICS.dbo.PROVDIR_HOS -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT spe.NPIis,spe.[Participating Network] COLLATE DATABASE_DEFAULT AS [Participating Network]
,CAST(NULL AS datetime) AS [WHEN_PROVIDER_ADDED]
,(LTRIM(RTRIM(spe.[Type of Service]))) AS [Specialty] -- THE CODE...
,' Hospitals ' AS SPEC --HARDCODE!!!
,spe.CityIs,spe.[Zip Code]
,ISNULL(CAST(spe.HospitalName AS nvarchar(100)),'')+' '+ISNULL(CAST(spe.HOSPabbrev AS nvarchar(100)),'')+' ID# '+ISNULL(CAST(spe.provider_no AS nvarchar(25)),'') COLLATE DATABASE_DEFAULT AS [TESTING]
--,spe.HospitalName+' '+spe.HOSPabbrev+' ID# '+spe.provider_no AS TESTING
,spe.HOSPabbrev,spe.provider_no,spe.REGION,spe.HospitalName
--,spe.FirstName,spe.TypeOfLicensure --DEPRECATED FROM FACILITY PROVDIR [TABLE](s)
,SUBSTRING(REPLACE((LTRIM(RTRIM(spe.HospitalName))),'.',''),1,255) AS INDEXNM
,CAST(SUBSTRING(REPLACE((LTRIM(RTRIM(spe.HospitalName))),'.','')+' '
+CASE
WHEN spe.HOSPabbrev COLLATE DATABASE_DEFAULT IS NULL
THEN ' '
ELSE (LTRIM(RTRIM(spe.HOSPabbrev))) COLLATE DATABASE_DEFAULT
END
+' - ID# '
+CASE
WHEN spe.provider_no COLLATE DATABASE_DEFAULT IS NULL
THEN ' '
