	OR (LTRIM(RTRIM(spe.ServiceCategoryTypeName))) LIKE '%HOSPITAL%' -- LEFT JOIN (SELECT DISTINCT PracticeID,ClassOrCategory, ServiceTypeName,ServiceCategoryTypeName FROM eVips_chgcv.dbo.vwLocationServices WHERE ServiceTypeName LIKE '%GROUP%SPEC%') AS vls ON vp.PracticeID = vls.PracticeID -- DEFINE FAC CHAPTER(s) 
) --CONCLUDE ...		
