UPDATE INFORMATICS.dbo.PROVDIR_HOSMH
SET FINALhosp = CASE
WHEN HOSP1 IS NULL
	AND HOSP2 IS NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN 'NONE'
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
	AND HOSP3 IS NULL
