SELECT DISTINCT tafac.NPIis,tafac.[Participating Network] COLLATE DATABASE_DEFAULT AS [Participating Network]
,CAST(NULL AS datetime) AS [WHEN_PROVIDER_ADDED]
,(LTRIM(RTRIM(tafac.[Type of Service]))) AS [Specialty] -- THE CODE...
,'ICF (INTERMEDIATE CARE FACILITY)' AS SPEC --HARDCODE!!!
,tafac.CityIs,tafac.[Zip Code]
,ISNULL(CAST(tafac.HospitalName AS nvarchar(100)),'')+' '+ISNULL(CAST(tafac.HOSPabbrev AS nvarchar(100)),'')+' ID# '+ISNULL(CAST(tafac.provider_no AS nvarchar(25)),'') COLLATE DATABASE_DEFAULT AS [TESTING]
