--,[PROVIDER_TYPEdescr] AS [PROVIDER_TYPE]
,CAST((LTRIM(RTRIM('Intermediate Care Facility'))) AS nvarchar(255)) AS [PROVIDER_TYPE]
,group_name
,tafac.[ACCREDITATION] -- ADD per MS. K Callies ON 20170323
,tafac.[ACCREDITATION_BY] -- ADD per MS. K Callies ON 20170323
,tafac.lookup_key
,tafac.[URL_WEBSITE]
,tafac.[TTY] AS [AFTERHOURS_PHONE]
,tafac.[FAXnumber],tafac.[EMAILis]
,[CCSPaneledProvider] -- ADD TO FAC / SITE [TABLE(S)] AS OF 20220215
,[MedicaidMedicareFlag]
,[MMF]
,[FUTURE_TERM]
,[Telehealth_Indicator]
,[COUNTY] -- C007: APPLICABLE TO PROVIDERS ONLY!!! ADD - ON PER EMAIL FROM MS JOHANNA BASED UPON DHCS FINDING (LEVERAGE: APL 25-014 AND OR "PROVDIR Telehealth Indicator evips location .msg")
INTO INFORMATICS.dbo.PROVDIR_ICF
