	-- AND (LTRIM(RTRIM(ISNULL(tafac.NPIis,''))))  IN ('1073736427','1831124890','1639392079','1336368984','1114124849','1053518779','1134342520','1417183831','1982839320','1922233469','1679708028','1699901017','1477789832','1972739399','1881820207','1164658589','1205061645','1659506012','1154557577','1922277698','1427284843','1063648483') -- ICF NPI(S) FROM SIR SALIM FILE see "COC_SURVEY_..."
	AND tafac.[vlpSTATUSTYPENAME] LIKE 'ACTIVE%' --•	ADD ON TO FAC per PROVDIR meeting ON 20171226
	
