		OR (LTRIM(RTRIM(spe.[Type of Service FOCUS]))) LIKE '%CBAS%' 
		-- OR LTRIM(RTRIM(spe.NPIis)) IN ('1598882169')  --WHERE LTRIM(RTRIM([Type of Service])) = 'CBAS'	 	OR LTRIM(RTRIM(spe.NPIis)) = '1598882169'
			AND spe.[vlpSTATUSTYPENAME] LIKE 'ACTIVE%' --•	ADD ON TO FAC per PROVDIR meeting ON 20171226

DELETE
