		-- 'You will find ## Facilities / Centers to choose from in this section.'

UPDATE INFORMATICS.dbo.PROVDIR_IHSS
SET [CHAPTER_COUNT] = SUBSTRING('You will find '+[UNIQUErecords]+' Facilities / Centers to choose from in this section.',1,255)
FROM INFORMATICS.dbo.PROVDIR_IHSS AS pdir
	INNER JOIN #COUNT_IHSS AS cp ON pdir.[Participating Network] = cp.[Participating Network]
	
	
	
	
	
	

