UPDATE INFORMATICS.dbo.PROVDIR_IHSS
SET HOSP1 = (LTRIM(RTRIM(orig.HOSPabbrev))) --QUPD / CASE WHEN THEN ELSE END... USE provdir.HOSPabbrev
