------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS INFORMATICS.dbo.PROVDIR_DXC -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT spe.NPIis
,spe.[Participating Network] COLLATE DATABASE_DEFAULT AS [Participating Network]
-- ,'B' AS [Participating Network] -- INCLUDE ALL RECORDS REGARDLESS OF [Participating Network]
,CAST(NULL AS datetime) AS [WHEN_PROVIDER_ADDED]
,(LTRIM(RTRIM(spe.[Type of Service]))) AS [Specialty] -- THE CODE...
,' Hospitals ' AS SPEC --HARDCODE!!!
,spe.CityIs,spe.[Zip Code]
,ISNULL(CAST(spe.HospitalName AS nvarchar(100)),'')+' '+ISNULL(CAST(spe.HOSPabbrev AS nvarchar(100)),'')+' ID# '+ISNULL(CAST(spe.provider_no AS nvarchar(25)),'') COLLATE DATABASE_DEFAULT AS [TESTING]
--,spe.HospitalName+' '+spe.HOSPabbrev+' ID# '+spe.provider_no AS TESTING
,spe.HOSPabbrev,spe.provider_no,spe.REGION,spe.HospitalName
--,spe.FirstName,spe.TypeOfLicensure --DEPRECATED FROM FACILITY PROVDIR [TABLE](s)
,SUBSTRING(REPLACE((LTRIM(RTRIM(spe.HospitalName))),'.',''),1,255) AS INDEXNM
,CAST(SUBSTRING(REPLACE((LTRIM(RTRIM(spe.HospitalName))),'.','')+' '
+CASE
WHEN spe.HOSPabbrev COLLATE DATABASE_DEFAULT IS NULL
THEN ' '
ELSE (LTRIM(RTRIM(spe.HOSPabbrev))) COLLATE DATABASE_DEFAULT
END
+' - ID# '
+CASE
WHEN spe.provider_no COLLATE DATABASE_DEFAULT IS NULL
THEN ' '
ELSE (LTRIM(RTRIM(spe.provider_no))) COLLATE DATABASE_DEFAULT
END,1,255) AS nvarchar(255)) AS [PROVNM]
--,(LTRIM(RTRIM(spe.HospitalName)))+' '+(LTRIM(RTRIM(spe.HOSPabbrev)))+' - ID# '+(LTRIM(RTRIM(spe.provider_no))) AS PROVNM
,spe.[Clinic Name] -- SITE aka SERVICELOCATION
,spe.[DBA],spe.Address1,spe.Address2,spe.Address
,(LTRIM(RTRIM(spe.CityIs)))+', '+(LTRIM(RTRIM(spe.StateIs)))+' '+(LTRIM(RTRIM(spe.[Zip Code]))) AS CSZ
,(LTRIM(RTRIM(spe.[Zip Code]))) AS ZIP
,'('+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),1,3)+') '+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),5,3)+'-'+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),9,4) AS [Telephone Number]
----------------,spe.[Telephone Number]
,(LTRIM(RTRIM(spe.LocationID))) AS [Clinic QNXT provid] -- -Per S. Coleman email ON 20171229 '...Site code should be eVIPs unique Location ID ...'
-- ,[Clinic QNXT provid]
,spe.CA_License
-- ,'Yes' AS [BOARD CERTIFIED] -- HARDCODE!!! DFLT VAL() FOUND IN HISTORICAL SUBMISSION(s)
-- ,'Yes' AS [ACCEPTING NEW PATIENTS] -- HARDCODE!!! DFLT VAL() FOUND IN HISTORICAL SUBMISSION(s)
,CASE
WHEN (LTRIM(RTRIM(spe.[BoardCertified(Y/N)]))) = 'Y'
THEN 'Yes'
ELSE 'No'
END AS [BOARD CERTIFIED]
,CASE
WHEN (LTRIM(RTRIM(spe.[Accepting New Medi-Cal Members/ Referrals]))) = 'Y'
THEN 'Yes'
ELSE 'No'
END AS [ACCEPTING NEW PATIENTS]
-- ,'7 Days a Week, 24 Hours a Day' AS [Office Hour(s)] -- HARDCODE!!! DFLT VAL() FOUND IN HISTORICAL SUBMISSION(s)
,CASE
WHEN spe.[Office Hour(s)] IS NULL
THEN 'MON-FRI 8AM-5PM'
ELSE (LTRIM(RTRIM(spe.[Office Hour(s)]))) 
END AS [Office Hour(s)]
,'Yes' AS [ACCESS BY PUBLIC TRANSPORTATION] -- HARCODE!!! DFLT VAL() FOUND IN HISTORICAL SUBMISSION(s)
 ,spe.Accessibility,spe.[Accessibility Category(ies)] 
----------------,'Basic Access' AS Accessibility --HARDCODE!!! spe.Accessibility DFLT VAL() FOUND IN HISTORICAL SUBMISSION(s)
----------------,'P,EB,IB,W,R,E,T' AS [Accessibility Category(ies)] -- HARDCODE!!! spe.[Accessibility Category(ies)] DFLT VAL() FOUND IN HISTORICAL SUBMISSION(s) per S. Coleman ON 20160526 'Hospital' & 'SNF' Accessibility default if missing should be Basic Access with all of the accessibility codes.
--,CAST(NULL AS nvarchar(25)) [AGE RESTRICTION]AS  --QUPD / CASE WHEN THEN ELSE END... USE pcp.specialty AND pcp.age_restriction AND pcp.age-restriction2
,spe.[AGE RESTRICTION]
----------------,'Over 120 languages are spoken by medical staff or interpreters.' AS FINALlang --POSSIBLE MOVE TO FOOTER of HOS chapter IN GeoAccess DirectoryExpert
,SUBSTRING((LTRIM(RTRIM(ISNULL([FINALlang],'')))),1,255) AS [FINALlang] -- see INFORMATICS.dbo.[PROVDIR_FINALlang] AS fl
,Language1,Language2,Language3,Language4,Language5
,CAST(NULL AS nvarchar(125)) AS FINALhosp
,CAST(NULL AS nvarchar(25)) AS HOSP1,CAST(NULL AS nvarchar(25)) AS HOSP2,CAST(NULL AS nvarchar(25)) AS HOSP3,CAST(NULL AS nvarchar(25)) AS HOSP4,CAST(NULL AS nvarchar(25)) AS HOSP5  --QUPD / CASE WHEN THEN ELSE END... USE pcp.HOSPabbrev
,CAST(NULL AS nvarchar(255)) AS FINALhosp_FULL_NAME
,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME1,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME2,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME3,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME4,CAST(NULL AS nvarchar(100)) AS HOSP_FULL_NAME5  --QUPD / CASE WHEN THEN ELSE END... USE pcp.HOSPabbrev
,DefineOTH_SPE,spe.plan_type
,[ASSOCIATION GROUP]
--,[DEGREE DESCRIPTION]
,SUBSTRING(CAST(NULL AS nvarchar(255)),1,255) AS [DEGREE DESCRIPTION] -- PLACEHOLDER FOR FACILITY TABLES UNTIL FURTHER NOTICE
,[CULTURAL COMPETENCE]
,[HOSPITAL_IDENTIFICATION] -- NEED TO SPLIT HOSP TABLE INTO TWO (2) per S. COLEMAN ON 20160628 see 'GAH' General Acute Hospital
,@footnotedt+LTRIM(RTRIM(CASE 
WHEN DATEPART(WEEKDAY,@when) = 1 --SUNDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+5,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 2 --MONDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+4,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 3 --TUESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+3,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 4 --WEDNESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+2,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 5 --THURSDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+1,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 7 --SATURDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+6,101) AS nvarchar(10)) -- mm/dd/yyyy
ELSE CAST(CONVERT(varchar,CAST(@when AS datetime)+0,101) AS nvarchar(10)) -- mm/dd/yyyy
END)) AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
-- ,@footnotedt AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
,spe.[AREA_of_PRACTICE]
,CAST(NULL AS nvarchar(255)) AS [CHAPTER_COUNT],CAST('Diagnostic Centers' AS nvarchar(255)) AS [CHAPTER_NAME]
