	-- DEFINE CHAPTER COUNT(): 
------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #COUNT_DXC -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT [Participating Network]
,CASE
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))))))=6
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)))),1,3)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)))),4,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))))))=5
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)))),1,2)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)))),3,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))))))=4
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)))),1,1)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)))),2,3)
ELSE CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM([Address]))+LTRIM(RTRIM([HospitalName])) AS nvarchar(255)))) AS nvarchar(25)) 
END AS [UNIQUErecords]
INTO #COUNT_DXC
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.PROVDIR_DXC
GROUP BY [Participating Network]

		-- 'You will find ## Providers to choose from in this section.'
		-- 'You will find ## Facilities / Centers to choose from in this section.'

UPDATE INFORMATICS.dbo.PROVDIR_DXC
SET [CHAPTER_COUNT] = SUBSTRING('You will find '+[UNIQUErecords]+' Facilities / Centers to choose from in this section.',1,255)
FROM INFORMATICS.dbo.PROVDIR_DXC AS pdir
	INNER JOIN #COUNT_DXC AS cp ON pdir.[Participating Network] = cp.[Participating Network]
	
	
	
	
	
	

