-- OR LTRIM(RTRIM(spe.NPIis)) IN ('1467458620','1336538404') --WHERE LTRIM(RTRIM([Type of Service])) = 'DLC'	 	OR LTRIM(RTRIM(spe.NPIis)) IN ('1467458620','1336538404') --WHERE... OR...
