	AND orig.HOSPabbrev COLLATE DATABASE_DEFAULT != provdir.HOSP3 COLLATE DATABASE_DEFAULT
	
UPDATE INFORMATICS.dbo.PROVDIR_DLC
SET HOSP5 = (LTRIM(RTRIM(orig.HOSPabbrev))) --QUPD / CASE WHEN THEN ELSE END... USE provdir.HOSPabbrev
-- SELECT orig.HOSPabbrev,provdir.* -- CHECK 1st
FROM INFORMATICS.dbo.PROVDIR_DLC AS provdir
	INNER JOIN INFORMATICS.dbo.TimelyAccessFAC AS orig ON provdir.NPIis = orig.NPIis
