	AND orig.HOSPabbrev COLLATE DATABASE_DEFAULT != provdir.HOSP1 COLLATE DATABASE_DEFAULT
	AND orig.HOSPabbrev COLLATE DATABASE_DEFAULT != provdir.HOSP2 COLLATE DATABASE_DEFAULT
	AND orig.HOSPabbrev COLLATE DATABASE_DEFAULT != provdir.HOSP3 COLLATE DATABASE_DEFAULT
	AND orig.HOSPabbrev COLLATE DATABASE_DEFAULT != provdir.HOSP4 COLLATE DATABASE_DEFAULT
	
UPDATE INFORMATICS.dbo.PROVDIR_DLC
SET FINALhosp = CASE
WHEN HOSP1 IS NULL
	AND HOSP2 IS NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN 'NONE'
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))+', '+(LTRIM(RTRIM(HOSP2)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
	AND HOSP3 IS NOT NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))+', '+(LTRIM(RTRIM(HOSP2)))+', '+(LTRIM(RTRIM(HOSP3)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
	AND HOSP3 IS NOT NULL
	AND HOSP4 IS NOT NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))+', '+(LTRIM(RTRIM(HOSP2)))+', '+(LTRIM(RTRIM(HOSP3)))+', '+(LTRIM(RTRIM(HOSP4)))
ELSE (LTRIM(RTRIM(HOSP1)))+', '+(LTRIM(RTRIM(HOSP2)))+', '+(LTRIM(RTRIM(HOSP3)))+', '+(LTRIM(RTRIM(HOSP4)))+', '+(LTRIM(RTRIM(HOSP5)))
END
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
FROM INFORMATICS.dbo.PROVDIR_DLC AS provdir







