	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN 'NONE'
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
	AND HOSP3 IS NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))+', '+(LTRIM(RTRIM(HOSP2)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
	AND HOSP3 IS NOT NULL
	AND HOSP4 IS NULL
	AND HOSP5 IS NULL
THEN (LTRIM(RTRIM(HOSP1)))+', '+(LTRIM(RTRIM(HOSP2)))+', '+(LTRIM(RTRIM(HOSP3)))
WHEN HOSP1 IS NOT NULL
	AND HOSP2 IS NOT NULL
