------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS INFORMATICS.dbo.PROVDIR_CLINIC -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT DISTINCT spe.NPIis,CA_License
,spe.[Participating Network] COLLATE DATABASE_DEFAULT AS [Participating Network] -- per SCOLEMAN email ON 20180723 '...Yes, all of the facilities should be by LOB and have the focus, specialties, age restrictions be based ON each separate LOB record.  These support services were just for CMC when we started CMC, then somewhere down the line David contracted with them for MC also except for IHSS...'
-- ,'B' AS [Participating Network] -- INCLUDE ALL RECORDS REGARDLESS OF [Participating Network]
,CAST(NULL AS datetime) AS [WHEN_PROVIDER_ADDED]
,vlpSERVICETYPENAME AS [Specialty]
,'Community Health Centers' AS SPEC --HARDCODE!!!
,spe.CityIs,spe.[Zip Code]
,SUBSTRING(REPLACE((LTRIM(RTRIM(spe.[Clinic Name]))),'.',''),1,255) AS INDEXNM
,SUBSTRING(REPLACE((LTRIM(RTRIM(spe.[Clinic Name]))),'.',''),1,255) AS PROVNM
--,(LTRIM(RTRIM(spe.LastName)))+' '+(LTRIM(RTRIM(spe.HOSPabbrev)))+' - ID# '+(LTRIM(RTRIM(spe.provider_no))) AS PROVNM
,spe.[Clinic Name] -- SITE aka SERVICELOCATION
,spe.[DBA],spe.Address1,spe.Address2,spe.Address
,(LTRIM(RTRIM(spe.CityIs)))+', '+(LTRIM(RTRIM(spe.StateIs)))+' '+(LTRIM(RTRIM(spe.[Zip Code]))) AS CSZ
,(LTRIM(RTRIM(spe.[Zip Code]))) AS ZIP
,'('+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),1,3)+') '+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),5,3)+'-'+SUBSTRING(LTRIM(RTRIM(spe.[Telephone Number])),9,4) AS [Telephone Number]
----------------,spe.[Telephone Number]
,(LTRIM(RTRIM(spe.LocationID))) AS [Clinic QNXT provid] -- -Per S. Coleman email ON 20171229 '...Site code should be eVIPs unique Location ID ...'
-- ,[Clinic QNXT provid]
,spe.[AGE RESTRICTION]
--,spe.LANG1,spe.LANG2,spe.LANG3,spe.LANG4
----------------,'Over 120 languages are spoken by medical staff or interpreters.' AS FINALlang --POSSIBLE MOVE TO FOOTER of HOS chapter IN GeoAccess DirectoryExpert
,SUBSTRING((LTRIM(RTRIM(ISNULL([FINALlang],'')))),1,255) AS [FINALlang] -- see INFORMATICS.dbo.[PROVDIR_FINALlang] AS fl
,Language1,Language2,Language3,Language4,Language5
,[ASSOCIATION GROUP]
--,[DEGREE DESCRIPTION]
,SUBSTRING(CAST(NULL AS nvarchar(255)),1,255) AS [DEGREE DESCRIPTION] -- PLACEHOLDER FOR FACILITY TABLES UNTIL FURTHER NOTICE
,[CULTURAL COMPETENCE]
--,[HOSPITAL_IDENTIFICATION] -- NEED TO SPLIT HOSP TABLE INTO TWO (2) per S. COLEMAN ON 20160628 see 'GAH' General Acute Hospital
,CASE
WHEN spe.[Office Hour(s)] IS NULL -- CHANGE per SANDRA REQUEST ON 20210212 "SUBJECT:Directory Hours Update"
THEN 'MON-FRI 8AM-5PM' --DFLT VAL()
ELSE (LTRIM(RTRIM(h.[Office Hour(s)]))) -- CHANGE per SANDRA REQUEST ON 20210212 "SUBJECT:Directory Hours Update"
END AS [Office Hour(s)]
,'Yes' AS [ACCESS BY PUBLIC TRANSPORTATION]
----------------,Accessibility,[Accessibility Category(ies)]
,CASE
WHEN [Accessibility] IS NULL
THEN 'Basic Access'
ELSE (LTRIM(RTRIM([Accessibility])))
END AS [Accessibility]
,CASE
WHEN [Accessibility Category(ies)] IS NULL
THEN 'P, EB, IB, W, R, E,T'
ELSE (LTRIM(RTRIM([Accessibility Category(ies)])))
END AS [Accessibility Category(ies)]
,'Yes' AS [ACCEPTING NEW PATIENTS]
,@footnotedt+LTRIM(RTRIM(CASE 
WHEN DATEPART(WEEKDAY,@when) = 1 --SUNDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+5,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 2 --MONDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+4,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 3 --TUESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+3,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 4 --WEDNESDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+2,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 5 --THURSDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+1,101) AS nvarchar(10)) -- mm/dd/yyyy
WHEN DATEPART(WEEKDAY,@when) = 7 --SATURDAY
THEN CAST(CONVERT(varchar,CAST(@when AS datetime)+6,101) AS nvarchar(10)) -- mm/dd/yyyy
ELSE CAST(CONVERT(varchar,CAST(@when AS datetime)+0,101) AS nvarchar(10)) -- mm/dd/yyyy
END)) AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
-- ,@footnotedt AS [UPDATEDT_FOOTNOTE] -- PRESET TO NEXT FRIDAY
,spe.[AREA_of_PRACTICE]
,CAST(NULL AS nvarchar(255)) AS [CHAPTER_COUNT],CAST('Community Health Centers' AS nvarchar(255)) AS [CHAPTER_NAME]
-- ,[PROVIDER_TYPEdescr] AS [PROVIDER_TYPE]
,(LTRIM(RTRIM('Community Health Centers'))) AS PROVIDER_TYPE
,group_name
,spe.provider_no
,spe.[ACCREDITATION] -- ADD per MS. K Callies ON 20170323
,spe.[ACCREDITATION_BY] -- ADD per MS. K Callies ON 20170323
,spe.lookup_key
,spe.[URL_WEBSITE]
,spe.[TTY] AS [AFTERHOURS_PHONE]
,spe.[FAXnumber],spe.[EMAILis]
,[CCSPaneledProvider] -- ADD TO FAC / SITE [TABLE(S)] AS OF 20220215
,[MedicaidMedicareFlag]
,[MMF]
,[FUTURE_TERM]
,[Telehealth_Indicator]
,[COUNTY] -- C007: APPLICABLE TO PROVIDERS ONLY!!! ADD - ON PER EMAIL FROM MS JOHANNA BASED UPON DHCS FINDING (LEVERAGE: APL 25-014 AND OR "PROVDIR Telehealth Indicator evips location .msg")
INTO INFORMATICS.dbo.PROVDIR_CLINIC
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT [Office Hour(s)],Accessibility,[Accessibility Category(ies)],[CA_license] -- CHECK 1st
-- SELECT DISTINCT [Clinic Name] -- CHECK 1st
-- SELECT DISTINCT [CA_License] -- CHECK 1st
-- SELECT DISTINCT FacilityName,[CA_license] -- CHECK 1st
-- SELECT DISTINCT Accessibility,[Accessibility Category(ies)] -- CHECK 1st
FROM INFORMATICS.dbo.TimelyAccessCLINIC AS spe
	LEFT JOIN #HOURS_FAC AS h ON spe.PracticeID = h.PracticeID -- CHANGE per SANDRA REQUEST ON 20210212 "SUBJECT:Directory Hours Update"
		AND spe.LocationID = h.LocationID -- CHANGE per SANDRA REQUEST ON 20210212 "SUBJECT:Directory Hours Update"
WHERE spe.[CA_License] NOT LIKE '%[A-Z]%'  --ENTRY VOID OF ALPHA(s) aka ALL NUMERAL(s)...
	OR spe.[Clinic Name] LIKE '%SYCUAN%' -- ,(LTRIM(RTRIM(vpl.LocationName))) AS [Clinic Name] spe.[CA_License] IN ('PHE39873') aka SYCUAN
	OR spe.[Clinic Name] IN ('SOUTHERN INDIAN HEALTH COUNCIL')	 -- ,(LTRIM(RTRIM(vpl.LocationName))) AS [Clinic Name]







	-- DEFINE CHAPTER COUNT() --
------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #COUNT_CLINIC -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT [Participating Network]
,CASE
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))))))=6
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),1,3)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),4,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))))))=5
