THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),1,2)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),3,3)
WHEN LEN(LTRIM(RTRIM(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))))))=4
THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),1,1)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),2,3)
ELSE CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)) 
END AS [UNIQUErecords]
INTO #COUNT_PHARM
