THEN SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),1,1)+', '+SUBSTRING(LTRIM(RTRIM(CAST(COUNT(DISTINCT(CAST(LTRIM(RTRIM(Address))+LTRIM(RTRIM(PROVNM)) AS nvarchar(255)))) AS nvarchar(25)))),2,3)
