-------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
-------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS #PIVOTtesting -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')

SELECT [Participating Network],[RECORD COUNT],[NOTE(s)],[TOTAL],[UPDATEDT_FOOTNOTE]
INTO #PIVOTtesting
-- SELECT TOP 10 ' ' AS 'CHECK 1st',*
-- SELECT DISTINCT ' ' AS 'CHECK 1st'
FROM INFORMATICS.dbo.PROVDIR_CHAPTER_COUNT

		-- SELECT * FROM #PIVOTtesting

-- COALESCE() - ROW(s) INTO A SINGULAR STRING / COL(column); 3rd person present: coalesces; past tense: coalesced; past participle: coalesced; gerund or present participle: coalescing

					-- come together and form one mass or whole.
					-- "the puddles had coalesced into shallow streams"
					-- synonyms:	merge, unite, join together, combine, fuse, mingle, blend; amalgamate, consolidate, integrate, homogenize, converge
					-- "the puddles had coalesced into shallow streams"
					-- combine (elements) in a mass or whole.
					-- "to help coalesce the community, they established an office"

		-- STEP 01: Declare necessary variables
DECLARE @SQLQuery AS nvarchar (MAX)
DECLARE @PivotColumns AS nvarchar (MAX)
 
		-- STEP02: Get unique values of pivot column  
SELECT @PivotColumns = COALESCE(@PivotColumns + ',','')+ QUOTENAME([Participating Network]) --[] is the DEFAULT VAL() COALESCE() - ROW(s) INTO A SINGULAR STRING / COL(column)
-- SELECT @PivotColumns = COALESCE(@PivotColumns + ',','')+QUOTENAME ('character_string' , 'quote_character'  ) --[] is the DEFAULT VAL() COALESCE() - ROW(s) INTO A SINGULAR STRING / COL(column)
-- SELECT @PivotColumns = COALESCE(@PivotColumns + ',','')+ QUOTENAME(MOS,'"') --[] is the DEFAULT VAL() COALESCE() - ROW(s) INTO A SINGULAR STRING / COL(column)
-- SELECT @PivotColumns = COALESCE(@PivotColumns + ',','')+ QUOTENAME(MOS,'''') --[] is the DEFAULT VAL() COALESCE() - ROW(s) INTO A SINGULAR STRING / COL(column)
-- SELECT @PivotColumns = COALESCE(@PivotColumns + ',','')+ QUOTENAME(MOS,'|') --[] is the DEFAULT VAL() COALESCE() - ROW(s) INTO A SINGULAR STRING / COL(column)
FROM (SELECT DISTINCT [Participating Network] FROM #PIVOTtesting) AS PivotCOLnames ORDER BY [Participating Network] --SET PIVOT COL(s) HEADER(s) aka 'FOR'
 
-- SELECT @PivotColumns AS COLnames
-- SELECT * FROM #PIVOTtesting
 
-------------------------------------------------------------------------------------------------------------------------
	-- Error Trapping: Check If Permanent Table(s) Already Exist(s) And Drop If Applicable --
-------------------------------------------------------------------------------------------------------------------------
DROP TABLE IF EXISTS INFORMATICS.dbo.FINAL_PROVDIR_CHAPTER_COUNT -- SQL Server 2016 and later -- DYNAMIC tmp OR STATIC [TABLE] #TableName is a local temporary table visible only in the current session; #TableName is a GLOBAL temporary table visible to all sessions IN ('TempDB')
 
		-- STEP03: Create the dynamic query with all the values for 
-- pivot column at runtime
SET @SQLQuery = 
    'SELECT [NOTE(s)],[TOTAL],[UPDATEDT_FOOTNOTE] ,' -- ROW(s)
    +@PivotColumns -- SET PIVOT COL(s) HEADER(s) aka 'FOR'
    +' INTO INFORMATICS.dbo.FINAL_PROVDIR_CHAPTER_COUNT' --global temporary table visible to all sessions. 	
    +' FROM #PIVOTtesting'
    +' PIVOT(MAX([RECORD COUNT])' -- SET PIVOT VAL()
	+' FOR [Participating Network] IN ('+@PivotColumns+')) AS P' -- SET PIVOT COL(s) HEADER(s) aka 'FOR'
    +' ORDER BY [NOTE(s)],[TOTAL],[UPDATEDT_FOOTNOTE]'
 
					-- SELECT @SQLQuery AS [COPY & PASTE TO EXEC; MANUALLY]

-- x MS ACCESS QXTB COMPONENT(s)
		-- TRANSFORM defines the VAL() 
		-- SELECT defines the ROW(s)
		-- PIVOT defines the COLUMN - COL()

					EXEC sp_executesql @SQLQuery;

